// extracted from <script id="qd-v17-boot-mobile-helpers">
function todayDateOnly(){
  try{
    var d = new Date();
    var y = d.getFullYear();
    var m = String(d.getMonth()+1).padStart(2,'0');
    var day = String(d.getDate()).padStart(2,'0');
    return y + '-' + m + '-' + day;
  }catch(e){
    return new Date().toISOString().slice(0,10);
  }
}
window.todayDateOnly = todayDateOnly;
try{var todayDateOnly = window.todayDateOnly;}catch(e){}

function qdBootEsc(x){
  try{ if(typeof escHtml === 'function') return escHtml(x); }catch(e){}
  return String(x==null?'':x).replace(/[&<>"']/g,function(m){
    return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m];
  });
}
function qdBootVal(x){ return (x===undefined || x===null || x==='') ? '—' : qdBootEsc(x); }
function qdBootReadRow(label,value){
  return '<div class="m-read-row"><span>'+qdBootEsc(label)+'</span><b>'+qdBootVal(value)+'</b></div>';
}
function mobileStatusRead(l){
  l = l || {};
  var st = l.status || 'Chờ bốc';
  try{ if(typeof quickStatus === 'function') st = quickStatus(l); }catch(e){}
  return [
    qdBootReadRow('Trạng thái hiện tại', st),
    qdBootReadRow('Xuất phát', l.vnDepartAt),
    qdBootReadRow('Lấy mẫu', l.sampleAt),
    qdBootReadRow('Có KQ', l.resultAt),
    qdBootReadRow('Kiểm dịch', l.quarantineAt),
    qdBootReadRow('CO', l.coAt),
    qdBootReadRow('Thông quan / sang khẩu', l.borderAt || l.cnCrossAt),
    qdBootReadRow('Kiểm hóa', l.inspectionAt),
    qdBootReadRow('Hậu kiểm', l.postcheckType),
    qdBootReadRow('Bỏ hàng / sang xe', l.unloadAt || l.cnTransferAt),
    qdBootReadRow('Tới chợ', l.cnArriveAt),
    qdBootReadRow('Đang bán', l.sellingAt),
    qdBootReadRow('Đã bán', l.soldAt)
  ].join('');
}
window.mobileStatusRead = mobileStatusRead;

function mobileStatusEdit(l){
  try{ if(typeof lotStatusBlock === 'function') return lotStatusBlock(l); }catch(e){}
  return '<div class="hint">Không mở được form trạng thái.</div>';
}
window.mobileStatusEdit = mobileStatusEdit;

// extracted from <script>
const CONFIG_KEY='qd_supabase_config_v2';
function parseNum(v){
  if(typeof v==='number')return Number.isFinite(v)?v:0;
  let s=String(v??'').trim();
  if(!s)return 0;
  s=s.replace(/\s+/g,'').replace(/[^0-9,\.\-]/g,'');
  if(!s||s==='-'||s==='.'||s===',')return 0;
  const neg=s.startsWith('-');
  if(neg)s=s.slice(1);
  const dots=(s.match(/\./g)||[]).length, commas=(s.match(/,/g)||[]).length;
  function finish(x){const n=Number((neg?'-':'')+x);return Number.isFinite(n)?n:0}
  if(dots&&commas){
    const lastDot=s.lastIndexOf('.'), lastComma=s.lastIndexOf(',');
    const decSep=lastDot>lastComma?'.':',';
    const intSep=decSep==='.'?',':'.';
    const tail=s.slice(Math.max(lastDot,lastComma)+1);
    if(tail.length>0&&tail.length<=2){
      return finish(s.replaceAll(intSep,'').replace(decSep,'.'));
    }
    return finish(s.replace(/[\.,]/g,''));
  }
  const sep=dots?'.':(commas?',':'');
  if(sep){
    const parts=s.split(sep);
    if(parts.length>2){
      const tail=parts[parts.length-1];
      const allThousand=parts.slice(1).every(p=>p.length===3);
      if(allThousand)return finish(parts.join(''));
      if(tail.length>0&&tail.length<=2)return finish(parts.slice(0,-1).join('')+'.'+tail);
      return finish(parts.join(''));
    }
    const tail=parts[1]||'';
    if(tail.length===3)return finish(parts.join(''));
    if(tail.length>0&&tail.length<=2)return finish(parts[0]+'.'+tail);
    return finish(parts.join(''));
  }
  return finish(s);
}
function n(v){return parseNum(v)}
function fmtNum(x){return Number(n(x)||0).toLocaleString('vi-VN')}
function fmt(v,cur=''){const value=Math.round(n(v)*100)/100;return value.toLocaleString('vi-VN')+(cur?' '+cur:'')}
function key(){return Array.from(arguments).map(x=>canonicalCode(x)||'').join('||')}
function add(map,k,v){map.set(k,(map.get(k)||0)+n(v))}
function rows(map,cols){return Array.from(map.entries()).map(([k,v])=>{const p=k.split('||'),r={amount:v};cols.forEach((c,i)=>r[c]=p[i]);return r}).filter(r=>Math.abs(r.amount)>0.000001).sort((a,b)=>String(a[cols[0]]).localeCompare(String(b[cols[0]]))||String(a.currency||'').localeCompare(String(b.currency||'')))}
function costDiff(s){return n(s.costCharge)-n(s.costActual)}
function payableSale(s){return n(s.saleAmount)-n(s.commission)-n(s.costCharge)-n(s.otherCost)-n(s.compensation)}
function quangIncome(s){return n(s.commission)+costDiff(s)}
