function itemTabIndex(row,col,rowCount){return ''}
function itemRowEdit(x,row=0,rowCount=1){
  return `<tr><td>${itemVarietySelect(x.id,x.variety,itemTabIndex(row,1,rowCount))}</td><td>${itemInput(x.id,'grade',x.grade,itemTabIndex(row,2,rowCount))}</td><td>${itemSpecNum(x.id,x.spec||x.kgPerBox||9,itemTabIndex(row,3,rowCount))}</td><td>${itemNum(x.id,'boxes',x.boxes,itemTabIndex(row,4,rowCount))}</td><td>${itemNum(x.id,'totalKg',x.totalKg,itemTabIndex(row,5,rowCount))}</td><td>${itemNum(x.id,'salePrice',x.salePrice,itemTabIndex(row,6,rowCount))}</td><td>${itemNum(x.id,'saleAmount',x.saleAmount,itemTabIndex(row,7,rowCount))}</td><td>${itemInput(x.id,'markText',x.markText||extractMark(x.note),itemTabIndex(row,8,rowCount))}</td><td>${itemInput(x.id,'remark',x.remark||'',itemTabIndex(row,9,rowCount))}</td><td><button class="danger smallbtn" onclick="delLotItem('${x.id}')">Xoá</button></td></tr>`;
}
function editItemsOn(lotId){editingItemLots.add(lotId);renderLots()}
function editItemsOff(lotId){editingItemLots.delete(lotId);renderLots()}
function lotItemsBlock(l){
  const items=lotItems(l.id), totals=itemTotalsFor(l.id), vars=itemVarieties();
  const cb='price_'+l.id;
  const editing=editingItemLots.has(l.id)||!items.length;
  const datalist=`<datalist id="itemVarietyList">${vars.map(v=>`<option value="${v}"></option>`).join('')}</datalist>`;
  const actions = editing
    ? `${items.length?`<button class="primary smallbtn" onclick="editItemsOff('${l.id}')">Ghi hàng / hiện bảng</button>`:''}<button class="smallbtn" onclick="addLotItem('${l.id}')">+ Dòng hàng</button><button class="smallbtn" onclick="exportLotChinese('${l.id}')">Xuất list tiếng Trung</button>`
    : `<span class="item-edit-note">List đã ghi</span><button class="smallbtn" onclick="editItemsOn('${l.id}')">Sửa list</button><button class="smallbtn" onclick="exportLotChinese('${l.id}')">Xuất list tiếng Trung</button>`;
  return`<div class="subcard"><div class="subhead"><span>3. List hàng</span><div class="inline-actions"><label class="small"><input type="checkbox" id="${cb}"> Hiện đơn giá khi xuất</label>${actions}</div></div><div class="subbody">${datalist}<div class="hint">Cột <b>记号</b> dùng cho 2 đai trắng/3 đai vàng; khi xuất tiếng Trung app tự đổi thành 2条白带/3条黄带. Cột <b>备注</b> là ghi chú phụ riêng. Khi list đã ghi xong, bảng sẽ chỉ hiển thị; bấm <b>Sửa list</b> mới hiện ô nhập. <b>Phím Tab trong bảng hàng sẽ đi xuống theo cột</b> để nhập nhiều dòng nhanh hơn.</div><div class="item-tab-hint">Tab: Chủng loại dòng 1 → Chủng loại dòng 2 → ... rồi mới sang cột Loại.</div><div class="item-total-bar"><div class="item-total-card"><div class="label">Tổng số kiện/thùng</div><div class="val">${fmt(totals.boxes,'thùng')}</div></div><div class="item-total-card"><div class="label">Tổng kg</div><div class="val">${fmt(totals.kg,'kg')}</div></div><div class="item-total-card"><div class="label">Tổng tiền hàng theo list</div><div class="val">${fmt(totals.amount,l.currency)}</div></div></div><div class="table-wrap"><table class="lot-table ${editing?'edit-mode':'view-mode'}"><thead><tr><th class="col-variety">Chủng loại</th><th class="col-grade">Loại</th><th class="col-spec">Quy cách</th><th class="col-boxes">Thùng</th><th class="col-kg">Tổng kg</th><th class="col-price">Đơn giá</th><th class="col-money">Thành tiền</th><th class="col-mark">记号</th><th class="col-remark">备注</th>${editing?'<th></th>':''}</tr></thead><tbody>${items.length?items.map((x,i)=>editing?itemRowEdit(x,i,items.length):itemRowView(x,l)).join(''):`<tr><td colspan="${editing?10:9}">Chưa có dòng hàng. Bấm + Dòng hàng để nhập.</td></tr>`}</tbody></table></div></div></div>`}

function defaultCostCategories(){return ['Luật VN','Luật TQ','Cước xe','Lưu ca','Cắm điện','Bến bãi','Sang xe','Công nhân','Slot','Bao bù','Phí vận chuyển & VAT','Phát sinh khác']}

function costCategories(){const s=new Set(defaultCostCategories());data.lotCosts.forEach(c=>{if(c.category)s.add(c.category)});return Array.from(s)}
function costInput(id,name,val){return`<input value="${val??''}" onchange="patchCost('${id}','${name}',this.value)">`}
function costCategoryInput(id,val){const dl='costCatList';return`<input list="${dl}" value="${val??''}" placeholder="Chọn/gõ khoản phí" onchange="patchCost('${id}','category',this.value)">`}
function costNum(id,name,val){const v=n(val)===0?'':(val??'');return`<input type="text" inputmode="decimal" step="any" value="${v}" placeholder="0" onfocus="this.select()" onclick="this.select()" onchange="patchCostNum('${id}','${name}',this.value)">`}
function costConfirmed(c){return !String(c.note||'').toLowerCase().includes('chưa chốt') && !String(c.note||'').toLowerCase().includes('demo')}

function exportLotCosts(id){const l=lotById(id);if(!l)return;const costs=lotCosts(id);const sumC=costs.filter(c=>c.currency==='CNY').reduce((a,b)=>a+n(b.amount),0),sumV=costs.filter(c=>c.currency==='VND').reduce((a,b)=>a+n(b.amount),0);const rows=costs.map((c,i)=>`<tr><td>${i+1}</td><td>${escHtml(c.category||'')}</td><td>${escHtml(fmt(c.amount,c.currency))}</td><td>${escHtml(c.payer||'')}</td><td>${costConfirmed(c)?'Đã chốt':'Chưa chốt'}</td><td>${escHtml(qdCostPublicNote(c)||'')}</td></tr>`).join('');const w=window.open('','_blank');if(!w){alert('Cho phép popup rồi bấm lại.');return}w.document.write(`<!doctype html><html><head><meta charset="utf-8"><title>QuangDuren Durian Online V16.4 demo mobile</title>

</head><body><button onclick="window.print()" style="float:right">In/Lưu PDF</button><h1>BẢNG TỔNG HỢP CHI PHÍ LÔ HÀNG</h1><div class="info"><div><b>Mã lô:</b> ${escHtml(l.code)}</div><div><b>Chủ hàng:</b> ${escHtml(pname(l.owner))}</div><div><b>Chợ:</b> ${escHtml(l.cnMarket||l.market||pname(l.stall))}</div><div><b>BKS:</b> ${escHtml(l.truck)}</div><div><b>Mooc VN/TQ:</b> ${escHtml([l.mooc,l.cnMooc].filter(Boolean).join(' / '))}</div><div><b>Ngày sang xe:</b> ${escHtml(l.cnTransferAt||'')}</div></div><table><thead><tr><th>STT</th><th>Khoản phí</th><th>Số tiền</th><th>Ví/người trả</th><th>Trạng thái</th><th>Ghi chú</th></tr></thead><tbody>${rows||'<tr><td colspan="6">Chưa có chi phí</td></tr>'}<tr class="total"><td colspan="2">Tổng CNY</td><td colspan="4">${fmt(sumC,'CNY')}</td></tr><tr class="total"><td colspan="2">Tổng VND</td><td colspan="4">${fmt(sumV,'VND')}</td></tr></tbody></table><p><b>Tiền bán CNY:</b> ${fmt(n(l.saleCny),'CNY')} &nbsp; <b>Tiền bán VND:</b> ${fmt(n(l.saleVnd),'VND')} &nbsp; <b>Tỷ giá tham khảo:</b> ${fmt(n(l.saleRateRef),'')}</p>

</body></html>`);w.document.close()}

function ownerAdvanceRows(owner){const c=calc();return c.ownerDebt.filter(r=>r.party===owner&&r.amount<0).map(r=>({currency:r.currency,amount:-r.amount}))}
function ownerAdvanceHint(owner,currency){const rows=ownerAdvanceRows(owner).filter(r=>!currency||r.currency===currency);if(!rows.length)return '';return `<div class="cost-warning"><b>Ứng trước chủ hàng:</b> ${rows.map(r=>fmt(r.amount,r.currency)).join(' · ')} chưa phân bổ. Khi chốt lô, Dashboard sẽ tự cấn ròng; anh có thể ghi chú số áp vào lô nếu cần.</div>`}

function lotCloseBlock(l){const t=lotTotals(l);const un=lotCosts(l.id).filter(c=>!costConfirmed(c));return`<div class="subcard"><div class="subhead">6. Chi tiết bán / chốt công nợ</div><div class="subbody">${un.length?`<div class="cost-warning">Còn ${un.length} khoản chi phí chưa chốt. Bản tổng bán/công nợ có thể chỉ là tạm tính.</div>`:''}${ownerAdvanceHint(l.owner,l.currency)}<div class="formgrid">${field('Tổng bán CNY',lotNum(l.id,'saleCny',l.saleCny))}${field('Tổng bán VND',lotNum(l.id,'saleVnd',l.saleVnd))}${field('Tỷ giá tham khảo',lotNum(l.id,'saleRateRef',l.saleRateRef))}${field('Tổng bán cũ/1 loại tiền',lotNum(l.id,'saleTotal',l.saleTotal))}${field('Hoa hồng Quang',lotNum(l.id,'commission',l.commission))}${field('Chi phí trừ CH',lotNum(l.id,'costCharge',l.costCharge))}${field('Chi phí thực chi chốt tay',lotNum(l.id,'costActual',l.costActual))}${field('Bao bù',lotNum(l.id,'compensation',l.compensation))}<div class="calcbox"><div class="label">Tổng bán theo list</div><div class="value">${fmt(t.itemAmount,l.currency)}</div></div><div class="calcbox"><div class="label">Phải trả CH</div><div class="value">${fmt(t.payable,l.currency)}</div></div><div class="calcbox"><div class="label">CP tính cho CH</div><div class="value">${fmt(t.costCharge,l.currency)}</div></div><div class="calcbox"><div class="label">Chênh CP</div><div class="value">${fmt(t.diff,l.currency)}</div></div><div class="calcbox"><div class="label">HH + chênh CP</div><div class="value">${fmt(t.income,l.currency)}</div></div></div><div class="actions" style="margin-top:10px"><button class="primary" onclick="syncLotToSale('${l.id}')">Chốt sang Ghi có lô hàng</button><button class="smallbtn" onclick="exportLotAccounting('${l.id}')">Xuất bảng hạch toán</button>${l.saleLocked?'<span class="cost-confirmed">Đã khóa ghi nhanh</span>':''}</div></div></div>`}

function localDateStr(){return todayStr()}

function lotYearValue(){
  const d=new Date();
  return String(d.getFullYear());
}
function lotDateCompact(){
  const d=new Date();
  return String(d.getFullYear()).slice(2)+String(d.getMonth()+1).padStart(2,'0')+String(d.getDate()).padStart(2,'0');
}

function ownerCodePrefix(owner){
  const p=data.parties.find(x=>x.code===owner);
  const src=(p?.code||owner||p?.name||'LO').toString();
  const raw=stripText(src).toUpperCase().replace(/[^A-Z0-9]/g,'');
  return raw.slice(0,12)||'LO';
}

function tempLotCode(){
  const y=lotYearValue();
  const count=(data.lots||[]).filter(l=>String(l.code||'').toUpperCase().startsWith('NHAP-'+y+'-')).length+1;
  return 'NHAP-'+y+'-'+String(count).padStart(3,'0');
}

function isAutoLotCode(code,owner){
  const c=String(code||'').toUpperCase();
  if(!c)return true;
  if(c.startsWith('NHAP-'))return true;
  if(/^[A-Z0-9]+-\d{6}-\d{2,3}$/.test(c))return true;
  if(owner){
    const p=ownerCodePrefix(owner);
    if(c.startsWith(p+'-'))return true;
  }
  return false;
}

function nextOwnerLotCode(owner,ignoreId=''){
  const p=ownerCodePrefix(owner);
  const y=lotYearValue();
  let max=0;
  (data.lots||[]).forEach(l=>{
    if(ignoreId&&l.id===ignoreId)return;
    const c=String(l.code||'').toUpperCase();
    let m=c.match(new RegExp('^'+p+'-'+y+'-(\\d+)$'));
    if(m)max=Math.max(max,Number(m[1]||0));
  });
  return p+'-'+y+'-'+String(max+1).padStart(3,'0');
}

async function addLot(){
  try{
    await requireLogin();
    const row={code:tempLotCode(),date:localDateStr(),owner:'',stall:'',currency:'CNY',status:'Đang theo dõi',market:'',brandCn:'',factoryDate:'',cnTransferAt:'',cnTruck:'',cnMooc:'',truck:'',mooc:'',containerNo:'',driverPhone:'',truckOwner:'',vnFrom:'',borderGate:'',vnLaw:'',vnDepartAt:'',vnCheckAt:'',temp:'',vent:'',vnFreight:0,layoverFee:0,plugFee:0,cnCrossAt:'',cnReceiver:'',cnMarket:'',cnArriveAt:'',cnCondition:'',cnYardFee:0,cnTransferFee:0,cnWorkerFee:0,slotFee:0,cnLawFee:0,saleTotal:0,saleCny:0,saleVnd:0,saleRateRef:0,saleLocked:false,commission:0,costCharge:0,costActual:0,compensation:0,sampleAt:'',resultAt:'',quarantineAt:'',coAt:'',borderAt:'',inspectionAt:'',postcheckType:'',unloadAt:'',sellingAt:'',soldAt:'',growCode:'',packCode:'',note:''};
    const {data:ins,error}=await supa.from('lots').insert(toLotDb(row)).select().single();
    if(error)throw error;
    const lot=fromLotDb(ins);
    data.lots=data.lots.filter(x=>x.id!==lot.id);
    data.lots.unshift(lot);
    selectedLotId=lot.id;
    lotEditState[lotEditKey(lot.id)]=true;
    const search=document.getElementById('lotSearch'); if(search)search.value='';
    msg('Đã tạo LÔ MỚI riêng: '+lot.code+'. Hãy nhập trên lô này, app sẽ không tự sửa lô cũ.');
    showTab('lots');
    setTimeout(()=>{selectedLotId=lot.id;renderLots();document.getElementById('lots')?.scrollIntoView({behavior:'smooth',block:'start'});},0);
  }catch(e){msg(e.message||String(e),'err')}
}

async function forceLotCodeByOwner(id){
  const l=lotById(id); if(!l)return;
  if(!l.owner){msg('Chưa chọn chủ hàng nên chưa tạo được mã lô.','err');return}
  l.code=nextOwnerLotCode(l.owner,id);
  keepLotSectionOpen(id,'basic');
  refreshVisible(); reopenLotDetails();
  try{await requireLogin();const {error}=await supa.from('lots').update(toLotDb(l)).eq('id',id);if(error)throw error;msg('Đã tạo lại mã lô: '+l.code)}catch(e){msg(e.message||String(e),'err')}
}

async function patchLot(id,field,val){
  const l=lotById(id);if(!l)return; const wasDraft=isDraftLot(l); if(wasDraft||lotEditState[lotEditKey(id)]) lotEditState[lotEditKey(id)]=true; if(['date','factoryDate','vnDepartAt','vnCheckAt','sampleAt','resultAt','quarantineAt','coAt','borderAt','inspectionAt','unloadAt','cnTransferAt','cnArriveAt','sellingAt','soldAt'].includes(field)) val=normalizeLotDate(val);
  const oldOwner=l.owner, oldCode=l.code;
  if(field==='code'){
    const newCode=String(val||'').trim().toUpperCase();
    if(newCode){
      const dup=data.lots.find(x=>x.id!==id && String(x.code||'').toUpperCase()===newCode);
      if(dup){msg('Mã lô '+newCode+' đã tồn tại ở lô '+pname(dup.owner)+'. Không lưu để tránh đè nhầm cont.','err');refreshVisible();reopenLotDetails();return;}
    }
    if(!isDraftLot(l) && oldCode && newCode && newCode!==String(oldCode).toUpperCase()){
      const ok=confirm(`Anh đang sửa mã lô đã có dữ liệu:\n\n${oldCode} → ${newCode}\n\nNếu đây là lô mới, hãy bấm + Lô mới trước. Vẫn sửa mã lô cũ này?`);
      if(!ok){refreshVisible();reopenLotDetails();return;}
    }
    val=newCode;
  }
  if(field==='owner'){
    if(oldOwner && val && val!==oldOwner && !isDraftLot(l)){
      const ok=confirm(lotOwnerChangeWarning(l,val));
      if(!ok){refreshVisible();reopenLotDetails();return;}
    }
  }
  if(['cnTruck','cnMooc','cnMarket','cnReceiver'].includes(field) && val && !l.cnTransferAt){l.cnTransferAt=(window.todayDateOnly?window.todayDateOnly():(new Date()).toISOString().slice(0,10));}
  if(field==='cnTruck' && val && !l.cnTruck && !l.unloadAt){l.unloadAt=(window.todayDateOnly?window.todayDateOnly():(new Date()).toISOString().slice(0,10));}
  l[field]=val;
  if(field==='owner'){
    if(val && (isAutoLotCode(oldCode,oldOwner)||String(oldCode||'').toUpperCase().startsWith('NHAP-'))) l.code=nextOwnerLotCode(val,id);
    if(!val && isAutoLotCode(oldCode,oldOwner)) l.code=tempLotCode();
  }
  keepLotSectionOpen(id,'basic');
  if(['truck','mooc','containerNo','driverPhone','truckOwner','vnFrom','borderGate','vnLaw','vnDepartAt','vnCheckAt','temp','vent','vnFreight','layoverFee','plugFee'].includes(field)) keepLotSectionOpen(id,'vn');
  if(['sampleAt','resultAt','quarantineAt','coAt','borderAt','inspectionAt','unloadAt','cnArriveAt','sellingAt','soldAt','postcheckType'].includes(field)) keepLotSectionOpen(id,'status');
  if(['cnCrossAt','cnTransferAt','cnTruck','cnMooc','cnReceiver','cnMarket','cnCondition','cnYardFee','cnTransferFee','cnWorkerFee','slotFee','cnLawFee'].includes(field)) keepLotSectionOpen(id,'cn');
  selectedLotId=id;
  refreshVisible(); reopenLotDetails();
  try{await requireLogin();const {error}=await supa.from('lots').update(toLotDb(l)).eq('id',id);if(error)throw error;if(l.saleLocked && ['owner','stall','market','cnMarket','truck','saleCny','saleVnd','saleTotal','saleRateRef','commission','costCharge','costActual','compensation'].includes(field)){await upsertSaleFromLot(l,true);msg('Đã cập nhật lại hạch toán của lô đã chốt.')}}catch(e){msg(e.message||String(e),'err')}
}

function patchLotNum(id,field,val){patchLot(id,field,n(val))}
async function delLot(id){if(!confirm('Xoá lô này và các dòng hàng/chi phí?'))return;try{await requireLogin();const {error}=await supa.from('lots').delete().eq('id',id);if(error)throw error;data.lots=data.lots.filter(x=>x.id!==id);data.lotItems=data.lotItems.filter(x=>x.lotId!==id);data.lotCosts=data.lotCosts.filter(x=>x.lotId!==id);selectedLotId=data.lots[0]?.id||'';renderAll()}catch(e){msg(e.message||String(e),'err')}}

