function patchItemNum(id,field,val){const x=data.lotItems.find(i=>i.id===id);if(!x)return;if(field==='spec'){x.spec=String(n(val)||'');x.kgPerBox=n(val)}else{x[field]=n(val)}recalcItem(x);patchItem(id,field,field==='spec'?x.spec:x[field])}
