function saleBaseFromLot(l){
  const t=lotTotals(l);
  const cny=n(l.saleCny)||((l.currency==='CNY')?t.sale:0), vnd=n(l.saleVnd)||((l.currency==='VND')?t.sale:0);
  const serviceCost=n(t.serviceCost), slotCost=n(t.slotCost);
  return {date:new Date().toISOString().slice(0,10),lot:l.code,truck:l.truck,owner:l.owner,stall:l.stall,market:l.cnMarket||l.market,currency:cny?'CNY':'VND',saleAmount:cny||vnd,commission:n(l.commission),costCharge:serviceCost,otherCost:slotCost,compensation:n(l.compensation),costActual:serviceCost,exchangeRate:l.saleRateRef,payableCny:cny?Math.max(0,t.payableCny):0,payableVnd:vnd?Math.max(0,t.payableVnd):(cny&&n(l.saleRateRef)?Math.max(0,t.payableCny*n(l.saleRateRef)):0),locked:true,note:'Chốt từ chi tiết lô hàng V18.50.1 - tách Lớp 1 Slot/sạp trừ và Lớp 2 Dịch vụ trừ CH'};
}
async function upsertSaleFromLot(l, silent=false){
  const base=saleBaseFromLot(l);
  const matches=(data.sales||[]).filter(s=>sameSaleLot(s.lot,l.code));
  let merged=0;
  if(matches.length){
    matches.sort((a,b)=>saleDedupeScore(b)-saleDedupeScore(a));
    const keep=matches[0];
    Object.assign(keep,base);
    const {error}=await supa.from('sales').update(toSaleDb(keep)).eq('id',keep.id);
    if(error)throw error;
    const delIds=matches.slice(1).map(x=>x.id).filter(Boolean);
    if(delIds.length){
      const {error:de}=await supa.from('sales').delete().in('id',delIds);
      if(de)throw de;
      data.sales=data.sales.filter(x=>!delIds.includes(x.id));
      merged=delIds.length;
    }
  }else{
    const {data:ins,error}=await supa.from('sales').insert(toSaleDb(base)).select().single();
    if(error)throw error;
    data.sales.push(fromSaleDb(ins));
  }
  l.saleLocked=true;
  l.status='Đã chốt tiền';
  l.costCharge=n(base.costCharge); l.costActual=n(base.costActual); l.slotFee=n(base.otherCost);
  const {error:le}=await supa.from('lots').update(toLotDb(l)).eq('id',l.id);
  if(le)throw le;
  if(!silent) msg(merged?`Đã cập nhật dòng chốt lô và gộp ${merged} dòng trùng.`:'Đã cập nhật/chốt lô sang Ghi có lô hàng.');
  return {merged};
}
async function syncLotToSale(id){
  try{
    await requireLogin();
    const l=lotById(id);if(!l)return;
    const adv=ownerAdvanceRows(l.owner).filter(r=>r.currency===l.currency);
    if(adv.length&&!confirm(`Chủ hàng ${pname(l.owner)} đang có ứng trước/chênh âm: ${adv.map(r=>fmt(r.amount,r.currency)).join(' · ')}.\n\nApp sẽ ghi doanh thu lô theo logic 2 lớp; Dashboard công nợ sẽ tự cấn ròng với khoản ứng trước. Tiếp tục chốt?`))return;
    await upsertSaleFromLot(l,false);
    renderAll();showTab('cnSales');
  }catch(e){msg(e.message||String(e),'err')}
}

function sameSaleLot(a,b){return String(a||'').trim().toUpperCase()===String(b||'').trim().toUpperCase()}
function saleBaseFromLot(l){
  const t=lotTotals(l);
  const cny=n(l.saleCny)||((l.currency==='CNY')?t.sale:0), vnd=n(l.saleVnd)||((l.currency==='VND')?t.sale:0);
  const serviceCost=n(t.serviceCost), slotCost=n(t.slotCost);
  return {date:new Date().toISOString().slice(0,10),lot:l.code,truck:l.truck,owner:l.owner,stall:l.stall,market:l.cnMarket||l.market,currency:cny?'CNY':'VND',saleAmount:cny||vnd,commission:n(l.commission),costCharge:serviceCost,otherCost:slotCost,compensation:n(l.compensation),costActual:serviceCost,exchangeRate:l.saleRateRef,payableCny:cny?Math.max(0,t.payableCny):0,payableVnd:vnd?Math.max(0,t.payableVnd):(cny&&n(l.saleRateRef)?Math.max(0,t.payableCny*n(l.saleRateRef)):0),locked:true,note:'Chốt từ chi tiết lô hàng V18.50.1 - tách Lớp 1 Slot/sạp trừ và Lớp 2 Dịch vụ trừ CH'};
}
async function upsertSaleFromLot(l, silent=false){
  const base=saleBaseFromLot(l);
  const matches=(data.sales||[]).filter(s=>sameSaleLot(s.lot,l.code));
  let merged=0;
  if(matches.length){
    matches.sort((a,b)=>saleDedupeScore(b)-saleDedupeScore(a));
    const keep=matches[0];
    Object.assign(keep,base);
    const {error}=await supa.from('sales').update(toSaleDb(keep)).eq('id',keep.id);
    if(error)throw error;
    const delIds=matches.slice(1).map(x=>x.id).filter(Boolean);
    if(delIds.length){
      const {error:de}=await supa.from('sales').delete().in('id',delIds);
      if(de)throw de;
      data.sales=data.sales.filter(x=>!delIds.includes(x.id));
      merged=delIds.length;
    }
  }else{
    const {data:ins,error}=await supa.from('sales').insert(toSaleDb(base)).select().single();
    if(error)throw error;
    data.sales.push(fromSaleDb(ins));
  }
  l.saleLocked=true;
  l.status='Đã chốt tiền';
  l.costCharge=n(base.costCharge); l.costActual=n(base.costActual); l.slotFee=n(base.otherCost);
  const {error:le}=await supa.from('lots').update(toLotDb(l)).eq('id',l.id);
  if(le)throw le;
  if(!silent) msg(merged?`Đã cập nhật dòng chốt lô và gộp ${merged} dòng trùng.`:'Đã cập nhật/chốt lô sang Ghi có lô hàng.');
  return {merged};
}
async function syncLotToSale(id){
  try{
    await requireLogin();
    const l=lotById(id);if(!l)return;
    const adv=ownerAdvanceRows(l.owner).filter(r=>r.currency===l.currency);
    if(adv.length&&!confirm('Chủ hàng '+pname(l.owner)+' đang có ứng trước '+adv.map(r=>fmt(r.amount,r.currency)).join(' · ')+'. Dashboard sẽ tự cấn ròng vào công nợ sau khi chốt lô. Tiếp tục chốt?'))return;
    await upsertSaleFromLot(l,false);
    await syncAll();
  }catch(e){msg(e.message||String(e),'err')}
}
async function repairDuplicateSales(){
  try{
    await requireLogin();
    let fixed=0;
    const lotsByKey=new Map((data.lots||[]).map(l=>[String(l.code||'').trim().toUpperCase(),l]));
    const salesByLot={};
    (data.sales||[]).forEach(s=>{const k=saleLotKey(s);if(k)(salesByLot[k]=salesByLot[k]||[]).push(s)});
    for(const l of (data.lots||[])){
      const k=String(l.code||'').trim().toUpperCase();
      if(!k)continue;
      if(l.saleLocked || salesByLot[k]){
        await upsertSaleFromLot(l,true);
        fixed++;
      }
    }
    msg(fixed?`Đã cập nhật lại hạch toán ${fixed} lô theo logic 2 lớp chi phí.`:'Không thấy lô đã chốt cần cập nhật.');
    await syncAll();
  }catch(e){msg(e.message||String(e),'err')}
}
function duplicateSaleCount(){const m={};(data.sales||[]).forEach(s=>{const k=saleLotKey(s);if(k)m[k]=(m[k]||0)+1});return Object.values(m).filter(x=>x>1).reduce((a,b)=>a+b-1,0)}
function renderSales(){const dup=duplicateSaleCount();const datalistLots=`<datalist id="saleLotList">${data.lots.map(l=>`<option value="${l.code}">${pname(l.owner)} · ${l.truck||''}</option>`).join('')}</datalist>`;const truckList=`<datalist id="truckList">${Array.from(new Set(data.lots.map(l=>l.truck).filter(Boolean))).map(x=>`<option value="${x}"></option>`).join('')}</datalist>`;document.getElementById('sales').innerHTML=`<div class="card"><div class="section"><div><h2>Ghi có lô hàng</h2><p class="small">Chọn Chủ hàng/BKS để gợi ý mã lô. Có tỷ giá tham khảo để tách công nợ CNY/VND.</p></div><div class="actions"><button class="smallbtn ${dup?'warnbtn':''}" onclick="repairDuplicateSales()">Rà/gộp & cập nhật hạch toán${dup?` (${dup})`:''}</button><span class="small">Dữ liệu nên chốt từ Chi tiết lô hàng; V18.50.1 tách đúng Lớp 1 Slot/sạp trừ và Lớp 2 Dịch vụ trừ CH.</span></div></div>${datalistLots}${truckList}<div class="hint">Fix16: Nếu chốt lô khi chưa chọn sạp, app vẫn ghi “Tôi nợ chủ hàng”, nhưng không đưa vào “Chủ sạp còn nợ Quang”. Khi bổ sung sạp và chốt lại, app cập nhật dòng cũ thay vì tạo dòng trùng.</div>${data.sales.map(r=>`<div class="entry"><div class="entry-head"><div><span class="badge">${r.lot||'Lô mới'}</span> <b>${pname(r.owner)}</b> / ${pname(r.stall)||'<span class="small">chưa gán sạp</span>'} ${r.locked?'<span class="cost-confirmed">Đã khoá</span>':''}</div><button class="danger smallbtn" onclick="delSale('${r.id}')">Xoá</button></div><div class="formgrid">${field('Ngày',inp('sales',r.id,'date',r.date,'date'))}${field('Chủ hàng',sel('sales',r.id,'owner',salesOwners(),r.owner,true))}${field('BKS',`<input list="truckList" value="${r.truck||''}" onchange="patch('sales','${r.id}','truck',this.value)">`)}${field('Mã lô',`<input list="saleLotList" value="${r.lot||''}" onchange="patch('sales','${r.id}','lot',this.value)">`)}${field('Chợ',inp('sales',r.id,'market',r.market))}${field('Chủ sạp',sel('sales',r.id,'stall',stalls(),r.stall,true))}${field('Loại tiền bán',`<select onchange="patch('sales','${r.id}','currency',this.value)"><option ${r.currency==='CNY'?'selected':''}>CNY</option><option ${r.currency==='VND'?'selected':''}>VND</option></select>`)}${field('Tổng bán',inpNum('sales',r.id,'saleAmount',r.saleAmount))}${field('Tỷ giá tham khảo',inpNum('sales',r.id,'exchangeRate',r.exchangeRate))}${field('Phải trả CNY',inpNum('sales',r.id,'payableCny',r.payableCny))}${field('Phải trả VND',inpNum('sales',r.id,'payableVnd',r.payableVnd))}${field('Hoa hồng Quang',inpNum('sales',r.id,'commission',r.commission))}${field('Chi phí dịch vụ trừ CH',inpNum('sales',r.id,'costCharge',r.costCharge))}${field('Chi phí slot/sạp trừ',inpNum('sales',r.id,'otherCost',r.otherCost))}${field('Chi phí dịch vụ thực chi',inpNum('sales',r.id,'costActual',r.costActual))}${field('Ghi chú',inp('sales',r.id,'note',r.note))}<div class="calcbox"><div class="label">Quy đổi tham khảo</div><div class="value">${r.currency==='CNY'&&n(r.exchangeRate)?fmt(payableSale(r)*n(r.exchangeRate),'VND'):fmt(payableSale(r),r.currency)}</div></div></div></div>`).join('')}</div>`}
const flowTypes=['Thu từ chủ sạp','Trả chủ hàng/NCC','Đổi nợ chủ hàng','Nhận tiền đổi hộ','Đối tác thanh toán','Người đổi thanh toán','Đối tác trả hộ chủ hàng','Bán CNY','Chuyển CNY đối tác','Chuyển CNY người đổi','Đổi tiền','Chuyển vị trí','Chi phí','付汇 nhận CNY','付汇 chuyển CNY','付汇 chốt tỷ giá','付汇 trả VND'];
const moneyFlowTypes=['Sạp trả vào ví Quang','Sạp chuyển cho chủ hàng','Trả chủ hàng','Đổi nợ chủ hàng','Chuyển vị trí'];
function isOpeningFlow(r){return ['Số dư đầu kỳ','Số dư quỹ đầu kỳ','Phải thu đầu kỳ','Phải trả đầu kỳ'].includes(r.type)}
function regularFlows(){return data.flows.filter(r=>!isOpeningFlow(r))}

function flowSummary(r){
  if(isAutoFeeFlow(r)) return `Phí Luật Bank 0.1% tự động trừ từ ${pname(r.from)}`;
  if(r.type==='Thu từ chủ sạp') return `${pname(r.from)} trả tiền, tiền vào ${pname(r.to)}`;
  if(r.type==='Sạp → Đối tác'||r.type==='Sạp → Người đổi') return `${pname(r.from)} trả tiền, chuyển thẳng vào ${pname(r.to)}`;
  if(r.type==='Nhận tiền đổi hộ') return `${pname(r.owner||'')} chuyển tiền cho Quang vào ${pname(r.to)} · tự cấn trừ nếu còn nợ`;
  if(r.type==='Chuyển CNY đối tác'||r.type==='Chuyển CNY người đổi') return `Chuyển CNY của Quang từ ${pname(r.from)} sang đối tác ${pname(r.to)}`;
  if(r.type==='Chuyển vị trí') return `Tiền của ${pname(r.owner||'QUANG')} từ ${pname(r.from)} sang ${pname(r.to)}`;
  if(r.type==='Đối tác thanh toán'||r.type==='Người đổi thanh toán') return `${pname(r.owner)} trả VND vào ${pname(r.to)}${r.note?'' : ''}`;
  if(r.type==='Đối tác trả hộ chủ hàng') return `${pname(r.owner)} trả VND hộ/cấn cho ${pname(r.to)}${r.ref?' · '+escHtml(r.ref):''}`;
  if(r.type==='Bán CNY') return `Bán ${fmt(r.amount,'CNY')} cho ${pname(r.to)} từ ${pname(r.from)} · phải thu ${fmt(r.toAmount||Math.round(n(r.amount)*n(r.rate)),'VND')}`;
  if(r.type==='Đổi tiền') return `${pname(r.from)} báo tỷ giá ${fmt(r.amount,r.currency)} → ${fmt(r.toAmount||Math.round(n(r.amount)*n(r.rate)),r.toCurrency||'VND')}${r.to?(' · cấn/vào '+pname(r.to)):' · chỉ giảm CNY ở đối tác'}`;
  if(r.type==='Đổi nợ chủ hàng') return `Chuyển đổi tiền ${pname(r.owner)}: ${fmt(r.amount,r.currency)} → ${fmt(r.toAmount||Math.round(n(r.amount)*n(r.rate)),r.toCurrency||'VND')}`;
  if(r.type==='Trả chủ hàng/NCC') return `Trả ${pname(r.owner||'')} bằng nguồn ${pname(r.from)}${r.to&&r.to!=='OUT'?' sang '+pname(r.to):''}`;
  if(r.type==='Chi phí') return `Chi từ ${pname(r.from)}`;
  return `${pname(r.from)} → ${pname(r.to)}`;
}

function flowSub(r){
  const parts=[];
  if(r.date)parts.push(r.date);
  if(r.ref)parts.push('Mã: '+r.ref);
  if(r.note)parts.push(r.note);
  return parts.join(' · ');
}

