function roleHintHtml(){return `<div class="v16-role-help"><div class="pill"><b>CS</b><span class="small">Chủ sạp/chợ trả tiền hàng.</span></div><div class="pill"><b>CH</b><span class="small">Chủ hàng được cấn công nợ.</span></div><div class="pill"><b>Ví</b><span class="small">Ví riêng của Quang: bank, tiền mặt, Alipay, WeChat, TM. Luật Bank hiển thị riêng là 付汇.</span></div><div class="pill"><b>ĐT</b><span class="small">Đối tác đa tiền tệ: Hương/Thương/Công VQ, có thể giữ CNY/VND và mua bán tệ.</span></div><div class="pill"><b>付汇</b><span class="small">Đổi hộ/giữ hộ qua Luật Bank 付汇, phí kê 0.1%, chốt tỷ giá theo mã.</span></div></div>`}
function partyGroupByRole(role){if(role==='CS')return {group:'Chủ sạp',owner:1,location:0};if(role==='CH')return {group:'Chủ hàng',owner:1,location:0};if(role==='VI')return {group:'Vị trí tiền',owner:0,location:1};if(role==='FH')return {group:'付汇',owner:1,location:0};if(role==='NDT'||role==='DT')return {group:'Đối tác đa tiền tệ',owner:1,location:1};return {group:'Khác',owner:0,location:0}}
function partyCodeExists(code){return data.parties.some(p=>String(p.code||'').toUpperCase()===String(code||'').toUpperCase())}
function fhCodeFromBase(raw){let base=String(raw||'').trim().toUpperCase().replace(/\s+/g,'_');if(!base)return '';if(base.includes('付汇'))base=base.replace('付汇','FH').replace(/__+/g,'_').replace(/^_|_$/g,'');if(!/(^|_)FH$/.test(base)&&!base.endsWith('_FUHUI'))base=base+'_FH';return base}
function selectPartyOption(selectId,p){const el=document.getElementById(selectId);if(!el||!p)return;let opt=Array.from(el.options||[]).find(o=>o.value===p.code);if(!opt){opt=document.createElement('option');opt.value=p.code;opt.textContent=p.code+' - '+(p.name||p.code);el.appendChild(opt);}el.value=p.code;}
async function addPartyByRole(role,selectId){try{await requireLogin();let raw=(prompt(role==='FH'?'Nhập tên/mã người 付汇, ví dụ VIC:':'Mã đối tượng mới:')||'').trim();if(!raw)return;let code=raw.toUpperCase().replace(/\s+/g,'_');let defaultName=raw;
  if(role==='FH'){
    const base=code;
    code=fhCodeFromBase(base);
    defaultName=raw.replace(/_?FH$/i,'').replace(/付汇/g,'').trim()||base;
    defaultName=defaultName+' 付汇';
  }
  const existing=data.parties.find(p=>String(p.code||'').toUpperCase()===code);
  if(existing){selectPartyOption(selectId,existing);msg('Đã chọn đối tượng đã có: '+existing.code+' - '+(existing.name||existing.code));return;}
  let name=prompt('Tên đối tượng:',role==='FH'?defaultName:code)||defaultName||code;
  if(role==='FH'&&!String(name).includes('付汇'))name+=' 付汇';
  const g=partyGroupByRole(role);const row={code,name,group:g.group,owner:g.owner,location:g.location};const {data:ins,error}=await supa.from('parties').insert(toPartyDb(row)).select().single();if(error)throw error;const p=fromPartyDb(ins);data.parties.push(p);selectPartyOption(selectId,p);msg('Đã thêm nhanh '+p.code+' - '+p.name);}catch(e){msg(e.message||String(e),'err')}}
function selectWithAdd(id,html,role,label='+ Thêm'){return `<div class="select-add">${html}<button type="button" onclick="addPartyByRole('${role}','${id}')">${label}</button></div>`}
function stallSelectAdd(id,val='',blank=true){return selectWithAdd(id,stallSelectHtml(id,val,blank),'CS','+ CS')}
function ownerSelectAdd(id,val='',blank=true){return selectWithAdd(id,customerOwnerSelectHtml(id,val,blank),'CH','+ CH')}
function walletSelectHtmlAdd(id,list,val='',blank=true){return `<select id="${id}">${opts(list,val,blank)}</select>`}
function walletSelectAdd(id,val='',blank=true){return selectWithAdd(id,walletSelectHtmlAdd(id,ownWallets(),val,blank),'VI','+ Ví')}
function cnyWalletSelectAdd(id,val='',blank=true){return selectWithAdd(id,walletSelectHtmlAdd(id,cnyOwnWallets(),val,blank),'VI','+ Ví CNY')}
function vndWalletSelectAdd(id,val='',blank=true){return selectWithAdd(id,walletSelectHtmlAdd(id,vndOwnWallets(),val,blank),'VI','+ Ví VND')}
function placeSelectAdd(id,val='',blank=true){return selectWithAdd(id,walletSelectHtmlAdd(id,uniqParties([...ownWallets(),...moneyChangers()]),val,blank),'DT','+ ĐT')}
function partnerSelectAdd(id,val='',blank=true){return selectWithAdd(id,moneyChangerSelectHtml(id,val,blank),'NDT','+ ĐT')}
function fhSelectHtml(id,val='',blank=true){return `<select id="${id}" onchange="if(window.updateFhChotHint)updateFhChotHint()">${flowOpt(fhParties(),val,blank)}</select>`}
function fhSelectAdd(id,val='',blank=true){return selectWithAdd(id,fhSelectHtml(id,val,blank),'FH','+ 付汇')}
function ownerCnyDebtParties(){const c=calc();const codes=new Set(c.ownerDebt.filter(r=>r.currency==='CNY'&&r.amount>0).map(r=>r.party));return salesOwners().filter(p=>codes.has(p.code)&&!isSelfOwner(p.code))}
function customerCnyDebtSelectHtml(id,val='',blank=true){return `<select id="${id}">${flowOpt(ownerCnyDebtParties(),val,blank)}</select>`}
function partnerMetric(c,code,type,cur){const arr=type==='detail'?c.detail.filter(r=>r.owner==='QUANG'&&r.location===code&&r.currency===cur):type==='ndt'?c.ndtDebt.filter(r=>r.party===code&&r.currency===cur):c.ownerDebt.filter(r=>r.party===code&&r.currency===cur);return arr.reduce((s,r)=>s+n(r.amount),0)}
function partnerDashboardCards(c){const ps=moneyChangers();if(!ps.length)return '';return `<div class="card"><div class="section"><div><h2>Tài khoản đối tác đa tiền tệ</h2><p class="small">Không hiển thị âm/dương: app diễn giải thành “đang giữ”, “tôi đang nợ”, “còn phải trả”.</p></div><button onclick="showTab('exchange')">Mở đối tác</button></div><div class="partner-grid">${ps.map(p=>partnerCard(p,c)).join('')}</div></div>`}
function partnerCard(p,c){
  const cny=partnerMetric(c,p.code,'detail','CNY'), vndHeld=partnerMetric(c,p.code,'detail','VND');
  const oweVnd=partnerMetric(c,p.code,'owner','VND'), oweCny=partnerMetric(c,p.code,'owner','CNY');
  const recvVnd=partnerMetric(c,p.code,'ndt','VND'), recvCny=partnerMetric(c,p.code,'ndt','CNY');
  const lines=[];
  if(cny>0)lines.push(['Đang giữ CNY của tôi',fmt(cny,'CNY')]);
  if(cny<0)lines.push(['Tôi cần bù CNY',fmt(-cny,'CNY'),'warn']);
  if(vndHeld>0)lines.push(['Đang giữ VND của tôi',fmt(vndHeld,'VND')]);
  if(recvCny>0)lines.push([`${escHtml(p.name||p.code)} còn phải trả tôi`,fmt(recvCny,'CNY')]);
  if(recvVnd>0)lines.push([`${escHtml(p.name||p.code)} còn phải trả tôi`,fmt(recvVnd,'VND')]);
  if(oweCny>0)lines.push([`Tôi đang nợ ${escHtml(p.name||p.code)}`,fmt(oweCny,'CNY'),'warn']);
  if(oweVnd>0)lines.push([`Tôi đang nợ ${escHtml(p.name||p.code)}`,fmt(oweVnd,'VND'),'warn']);
  return `<div class="partner-card"><h3>${escHtml(p.name||p.code)}</h3>${lines.length?lines.map(x=>`<div class="partner-line ${x[2]||''}"><span>${x[0]}</span><b>${x[1]}</b></div>`).join(''):'<div class="small">Đã cân bằng hoặc chưa có phát sinh.</div>'}</div>`;
}

function quickField(label,inner){return `<div class="field"><label>${label}</label>${inner}</div>`}
function quickMoney(id,placeholder='0'){return `<input id="${id}" type="text" inputmode="decimal" step="any" placeholder="${placeholder}" onfocus="this.select()" onclick="this.select()">`}
function setQuickTransfer(from,to,cur='CNY'){qset('q_from',from);qset('q_to',to);qset('q_cur',cur)}
function setQuickPay(owner,from,cur='VND'){qset('q_owner',owner);qset('q_from',from);qset('q_cur',cur)}
function setQuickExchange(from,to,cur='CNY',toCur='VND'){qset('q_from',from);qset('q_to',to);qset('q_cur',cur);qset('q_to_cur',toCur)}
function quickNote(id,placeholder='Ghi chú tự do'){return `<textarea id="${id}" rows="2" placeholder="${placeholder}"></textarea>`}

function quickFlowShortcuts(){
  if(!moneyFlowTypes.includes(flowQuickType)) return `<div class="flow-shortcuts"></div>`;
  if(flowQuickType==='Thu từ chủ sạp'){
    return `<div class="flow-shortcuts">${stalls().slice(0,8).map(s=>`<button onclick="qset('q_from','${s.code}')">Sạp ${escHtml(s.name)}</button>`).join('')}${wallets().slice(0,8).map(l=>`<button onclick="qset('q_to','${l.code}')">Tới ${escHtml(l.name)}</button>`).join('')}</div>`;
  }
  if(flowQuickType==='Nhận tiền đổi hộ'){
    return `<div class="flow-shortcuts">${moneyChangers().slice(0,8).map(o=>`<button onclick="qset('q_owner','${o.code}')">${escHtml(o.name)} chuyển</button>`).join('')}</div>`;
  }
  if(flowQuickType==='Chuyển CNY đối tác'){
    return `<div class="flow-shortcuts">${stalls().slice(0,6).map(s=>`<button onclick="qset('q_from','${s.code}')">Nguồn ${escHtml(s.name)}</button>`).join('')}${moneyChangers().slice(0,8).map(o=>`<button onclick="qset('q_to','${o.code}')">Cho ${escHtml(o.name)}</button>`).join('')}</div>`;
  }
  if(flowQuickType==='Chuyển vị trí'){
    return `<div class="flow-shortcuts"><button onclick="setQuickTransfer('LUATBANK','TM','CNY')">Luật Bank → TM CNY</button><button onclick="setQuickTransfer('ALIPAY','TM','CNY')">Alipay → TM CNY</button><button onclick="setQuickTransfer('WECHAT','TM','CNY')">WeChat → TM CNY</button><button onclick="setQuickTransfer('VCB','TM','VND')">VCB → TM VND</button></div>`;
  }
  if(flowQuickType==='Đổi tiền'){
    return `<div class="flow-shortcuts">${moneyChangers().slice(0,8).map(o=>`<button onclick="setQuickExchange('${o.code}','${o.code}','CNY','VND')">${escHtml(o.name)} báo tỷ giá</button>`).join('')}</div>`;
  }
  if(flowQuickType==='Đổi nợ chủ hàng'){
    return `<div class="flow-shortcuts">${salesOwners().filter(o=>!isSelfOwner(o.code)).slice(0,8).map(o=>`<button onclick="qset('q_owner','${o.code}')">Đổi nợ ${escHtml(o.name)}</button>`).join('')}</div>`;
  }
  if(flowQuickType==='Trả chủ hàng/NCC'){
    return `<div class="flow-shortcuts">${salesOwners().filter(o=>!isSelfOwner(o.code)).slice(0,8).map(o=>`<button onclick="setQuickPay('${o.code}','VCB','VND')">Trả ${escHtml(o.name)}</button>`).join('')}${stalls().slice(0,6).map(s=>`<button onclick="qset('q_from','${s.code}')">Nguồn ${escHtml(s.name)}</button>`).join('')}</div>`;
  }
  return `<div class="flow-shortcuts"></div>`;
}

