    f+=quickField('CH còn CNY',has?`<div class="select-add">${customerCnyDebtSelectHtml('q_owner','',true)}<button type="button" onclick="showTab('customers')">Xem CN</button></div>`:`<div class="readonly-box">Không có chủ hàng còn CNY</div>`);
    f+=quickField('Số CNY đổi',quickMoney('q_amount','Không vượt CNY còn lại'));
