async function saveConfig(){config.url=document.getElementById('cfgUrl').value.trim();config.key=document.getElementById('cfgKey').value.trim();localStorage.setItem(CONFIG_KEY,JSON.stringify(config));configEdit=false;initClient();await getSession();msg('Đã lưu cấu hình Supabase.');renderAll()}
async function testConnection(){try{initClient();await getSession();const {error}=await supa.from('parties').select('id').limit(1);if(error)throw error;msg('Kết nối Supabase OK.')}catch(e){msg(e.message||String(e),'err')}}
async function signUp(){try{initClient();const email=document.getElementById('authEmail').value.trim(),password=document.getElementById('authPass').value;const {error}=await supa.auth.signUp({email,password});if(error)throw error;msg('Đăng ký xong. Nếu yêu cầu xác nhận email, mở email xác nhận rồi đăng nhập.');await getSession()}catch(e){msg(e.message||String(e),'err')}}
async function signIn(){try{initClient();const email=document.getElementById('authEmail').value.trim(),password=document.getElementById('authPass').value;const {error}=await supa.auth.signInWithPassword({email,password});if(error)throw error;msg('Đăng nhập thành công.');await syncAll();await getSession();qdRenderAuthGate();showTab('dashboard')}catch(e){msg(e.message||String(e),'err');qdRenderAuthGate()}}
async function signOut(){try{if(supa)await supa.auth.signOut();session=null;data={parties:[],sales:[],flows:[],lots:[],lotItems:[],lotCosts:[]};msg('Đã đăng xuất.');renderAll();showTab('setup')}catch(e){msg(e.message||String(e),'err');qdRenderAuthGate()}}
async function seedParties(){try{await requireLogin();const {data:ex,error:e1}=await supa.from('parties').select('id').limit(1);if(e1)throw e1;if(ex&&ex.length){msg('Danh mục đã có dữ liệu, không nạp đè.');return}const {error}=await supa.from('parties').insert(defaultParties.map(toPartyDb));if(error)throw error;msg('Đã nạp danh mục mẫu.');await syncAll()}catch(e){msg(e.message||String(e),'err')}}

async function ensureLuatBankAutoFee(parent){
  if(!parent||!parent.id||!supa)return;
  const ref=autoFeeRef(parent.id);
  const localExisting=data.flows.find(x=>String(x.ref||'')===ref);
  if(needsLuatBankAutoFee(parent)){
    const fee=luatBankFeeAmount(parent);
    const feeLoc=isLuatBankCode(parent.from)?parent.from:parent.to;
    const direction=isLuatBankCode(parent.to)?'tiền vào Luật Bank':'tiền ra Luật Bank';
    const feeRow={date:parent.date||new Date().toISOString().slice(0,10),type:'Chi phí',ref,owner:parent.owner||'QUANG',from:feeLoc,to:'',currency:'CNY',amount:fee,rate:0,toCurrency:'',toAmount:0,feeLoss:0,note:`Tự động phí Luật Bank 0.1% (${direction}) cho ${pname(parent.owner||'QUANG')} · gốc ${fmt(n(parent.amount),'CNY')}`};
    if(localExisting){Object.assign(localExisting,feeRow);const {error}=await supa.from('flows').update(toFlowDb(localExisting)).eq('id',localExisting.id);if(error)throw error;}
    else{const {data:ins,error}=await supa.from('flows').insert(toFlowDb(feeRow)).select().single();if(error)throw error;data.flows.push(fromFlowDb(ins));}
  }else if(localExisting){const {error}=await supa.from('flows').delete().eq('id',localExisting.id);if(error)throw error;data.flows=data.flows.filter(x=>x.id!==localExisting.id);}
}
async function ensureAllLuatBankFees(){
  for(const fl of [...data.flows]){
    if(!isAutoFeeFlow(fl)) await ensureLuatBankAutoFee(fl);
  }
}
async function deleteLinkedAutoFee(parentId){
  const ref=autoFeeRef(parentId);
  const linked=data.flows.filter(x=>String(x.ref||'')===ref);
  for(const f of linked){
    const {error}=await supa.from('flows').delete().eq('id',f.id);
    if(error)throw error;
  }
  if(linked.length)data.flows=data.flows.filter(x=>String(x.ref||'')!==ref);
}

async function patch(tableName,id,name,val){const arr=tableName==='sales'?data.sales:data.flows,row=arr.find(x=>x.id===id);if(!row)return;row[name]=val;refreshVisible();try{await requireLogin();const payload=tableName==='sales'?toSaleDb(row):toFlowDb(row);const {error}=await supa.from(tableName).update(payload).eq('id',id);if(error)throw error;if(tableName==='flows')await ensureLuatBankAutoFee(row);msg('')}catch(e){msg(e.message||String(e),'err')}}
function patchNum(tableName,id,name,val){patch(tableName,id,name,n(val))}
async function addSale(){try{await requireLogin();const row={date:new Date().toISOString().slice(0,10),lot:'',truck:'',owner:'',stall:'',market:'',currency:'CNY',saleAmount:0,commission:0,costCharge:0,otherCost:0,compensation:0,costActual:0,exchangeRate:0,payableCny:0,payableVnd:0,locked:false,note:''};const {data:ins,error}=await supa.from('sales').insert(toSaleDb(row)).select().single();if(error)throw error;data.sales.push(fromSaleDb(ins));renderAll()}catch(e){msg(e.message||String(e),'err')}}

async function addOpening(type){
  try{
    await requireLogin();
    const row={date:new Date().toISOString().slice(0,10),type,ref:'OPENING',owner:'QUANG',from:'',to:'',currency:'CNY',amount:0,rate:0,toCurrency:'',toAmount:0,feeLoss:0,note:'Số dư đầu kỳ'};
    if(type==='Số dư quỹ đầu kỳ'){row.owner='QUANG';row.to=openingLocations()[0]?.code||'';}
    if(type==='Phải thu đầu kỳ'){row.owner='QUANG';row.from=openingReceivableParties()[0]?.code||'';}
    if(type==='Phải trả đầu kỳ'){row.owner=openingPayableParties()[0]?.code||'';}
    const {data:ins,error}=await supa.from('flows').insert(toFlowDb(row)).select().single();
    if(error)throw error;
    data.flows.push(fromFlowDb(ins));openingEditId=ins.id;renderAll()
  }catch(e){msg(e.message||String(e),'err')}
}

async function changeOpeningType(id,type){
  const row=data.flows.find(x=>x.id===id); if(!row)return;
  row.type=type; row.ref='OPENING';
  if(type==='Số dư quỹ đầu kỳ'){
    row.from='';
    if(!row.owner)row.owner='QUANG';
    if(!row.to)row.to=openingLocations()[0]?.code||'';
  }
  if(type==='Phải thu đầu kỳ'){
    row.owner='QUANG';
    row.to='';
    if(!openingReceivableParties().some(p=>p.code===row.from)) row.from=openingReceivableParties()[0]?.code||'';
  }
  if(type==='Phải trả đầu kỳ'){
    row.from=''; row.to='';
    if(!openingPayableParties().some(p=>p.code===row.owner)) row.owner=openingPayableParties()[0]?.code||'';
  }
  renderAll();
  try{await requireLogin();const {error}=await supa.from('flows').update(toFlowDb(row)).eq('id',id);if(error)throw error;await ensureLuatBankAutoFee(row)}catch(e){msg(e.message||String(e),'err')}
}

async function addFlow(type){try{await requireLogin();const row={date:new Date().toISOString().slice(0,10),type,ref:'',owner:'',from:'',to:'',currency:'CNY',amount:0,rate:0,toCurrency:'',toAmount:0,feeLoss:0,note:''};
if(type==='Thu từ chủ sạp'){row.from=stalls()[0]?.code||'';row.to=locs()[0]?.code||'';}
if(type==='Chuyển CNY đối tác'){row.owner='QUANG';row.from=locs()[0]?.code||'';row.to=owners().find(p=>!isSelfOwner(p.code))?.code||'';row.currency='CNY';}
if(type==='Chuyển vị trí'){row.owner='QUANG';row.from=locs()[0]?.code||'';row.to=locs()[1]?.code||'';}
if(type==='Đổi tiền'){row.owner='QUANG';row.from=locs()[0]?.code||'';row.to=locs()[1]?.code||'';row.toCurrency='VND';}
if(type==='Đổi nợ chủ hàng'){row.owner=salesOwners().find(p=>!isSelfOwner(p.code))?.code||'';row.currency='CNY';row.toCurrency='VND';}
if(type==='Trả chủ hàng/NCC'){row.owner=salesOwners().find(p=>!isSelfOwner(p.code))?.code||'';row.from=locs()[0]?.code||'';row.to='OUT';}
if(type==='Nhận tiền đổi hộ'){row.owner=owners().find(p=>!isSelfOwner(p.code))?.code||'';row.to=locs()[0]?.code||'';}
const {data:ins,error}=await supa.from('flows').insert(toFlowDb(row)).select().single();if(error)throw error;const nf=fromFlowDb(ins);data.flows.push(nf);await ensureLuatBankAutoFee(nf);flowEditId=ins.id;renderAll()}catch(e){msg(e.message||String(e),'err')}}
async function changeFlowType(id,type){
  const row=data.flows.find(x=>x.id===id); if(!row)return;
  row.type=type;
  if(row.ref==='OPENING')row.ref='';
  if(type==='Thu từ chủ sạp'){row.owner=''; if(!row.from)row.from=stalls()[0]?.code||''; if(!row.to)row.to=locs()[0]?.code||'';}
  if(type==='Chuyển CNY đối tác'){row.owner='QUANG'; if(!row.from)row.from=locs()[0]?.code||''; if(!row.to)row.to=owners().find(p=>!isSelfOwner(p.code))?.code||''; row.currency='CNY';}
  if(type==='Chuyển vị trí'){if(!row.owner)row.owner='QUANG'; if(!row.from)row.from=locs()[0]?.code||''; if(!row.to)row.to=locs()[1]?.code||'';}
  if(type==='Đổi tiền'){if(!row.owner)row.owner='QUANG'; if(!row.from)row.from=locs()[0]?.code||''; if(!row.to)row.to=locs()[1]?.code||''; if(!row.toCurrency)row.toCurrency=row.currency==='CNY'?'VND':'CNY';}
  if(type==='Đổi nợ chủ hàng'){if(!row.owner)row.owner=salesOwners().find(p=>!isSelfOwner(p.code))?.code||''; row.currency=row.currency||'CNY'; row.toCurrency=row.toCurrency||'VND'; row.from=''; row.to='';}
  if(type==='Trả chủ hàng/NCC'){if(!row.owner)row.owner=salesOwners().find(p=>!isSelfOwner(p.code))?.code||''; if(!row.from)row.from=locs()[0]?.code||''; if(!row.to)row.to='OUT';}
  if(type==='Nhận tiền đổi hộ'){if(!row.owner)row.owner=owners().find(p=>!isSelfOwner(p.code))?.code||''; if(!row.to)row.to=locs()[0]?.code||'';}
  renderAll();
  try{await requireLogin();const {error}=await supa.from('flows').update(toFlowDb(row)).eq('id',id);if(error)throw error}catch(e){msg(e.message||String(e),'err')}
}

async function delSale(id){if(!confirm('Xoá lô này?'))return;try{await requireLogin();const {error}=await supa.from('sales').delete().eq('id',id);if(error)throw error;data.sales=data.sales.filter(x=>x.id!==id);renderAll()}catch(e){msg(e.message||String(e),'err')}}
async function delFlow(id){if(!confirm('Xoá giao dịch này?'))return;try{await requireLogin();await deleteLinkedAutoFee(id);const {error}=await supa.from('flows').delete().eq('id',id);if(error)throw error;data.flows=data.flows.filter(x=>x.id!==id);if(openingEditId===id)openingEditId='';if(flowEditId===id)flowEditId='';renderAll()}catch(e){msg(e.message||String(e),'err')}}

function makePartyCode(name,kind){
  const words=stripText(name).toUpperCase().replace(/[^A-Z0-9]+/g,' ').trim().split(/\s+/).filter(Boolean);
  let base='';
  if(words.length>=2)base=words.map(w=>w[0]).join('');
  else base=(words[0]||'KH').slice(0,12);
  if(kind==='stall'&&!base.startsWith('CS'))base='CS'+base;
  if(!base)base=kind==='stall'?'CS':'KH';
  let code=base, i=2;
  const exists=c=>data.parties.some(p=>String(p.code).toUpperCase()===String(c).toUpperCase());
  while(exists(code)){code=base+i;i++}
  return code;
}

async function addPartyQuick(kind,lotId){
  try{
    await requireLogin();
    const label=kind==='stall'?'chủ sạp/chợ':'chủ hàng/khách';
    const name=(prompt('Tên '+label+' mới:')||'').trim();
    if(!name)return;
    let code=makePartyCode(name,kind);
    const custom=(prompt('Mã tự tạo là '+code+'. Anh có muốn sửa mã không?',code)||code).trim().toUpperCase().replace(/\s+/g,'_');
    if(custom)code=custom;
    const row={code,name,group:kind==='stall'?'Chủ sạp':'Chủ hàng',owner:kind==='stall'?0:1,location:kind==='stall'?1:0,note:'Tạo nhanh từ Chi tiết lô hàng'};
    const {data:ins,error}=await supa.from('parties').insert(toPartyDb(row)).select().single();
    if(error)throw error;
    const p=fromPartyDb(ins);data.parties.push(p);
    const l=lotById(lotId);
    if(l){
      const oldOwner=l.owner, oldCode=l.code;
      if(kind==='stall'){
        l.stall=p.code;
      }else{
        l.owner=p.code;
        if(isAutoLotCode(oldCode,oldOwner)) l.code=nextOwnerLotCode(p.code,lotId);
      }
      keepLotSectionOpen(lotId,'basic');
      const {error:e2}=await supa.from('lots').update(toLotDb(l)).eq('id',lotId);
      if(e2)throw e2;
    }
    msg('Đã thêm '+p.code+' - '+p.name+' và gắn vào lô hiện tại. '+(kind==='stall'?'':'Mã lô đã tự nhảy theo chủ hàng nếu đang là mã nháp.'));
    renderAll(); reopenLotDetails();
  }catch(e){msg(e.message||String(e),'err')}
}

async function addParty(){
  try{
    await requireLogin();
    const code=(prompt('Mã đối tượng, ví dụ HUONG, THUONG, BINHMINH, CSQC:')||'').trim().toUpperCase().replace(/\s+/g,'_');
    if(!code)return;
    const name=prompt('Tên đối tượng:',code)||code;
    const role=(prompt('Vai trò: nhập CH = chủ hàng, NDT = đối tác tiền, SAP = chủ sạp, VI = ví/bank, KHAC = khác','NDT')||'KHAC').trim().toUpperCase();
    let group='Khác', owner=0, location=0;
    if(role==='CH'){group='Chủ hàng';owner=1;location=0}
    else if(role==='NDT'||role==='DT'){group='Đối tác đa tiền tệ';owner=1;location=1}
    else if(role==='SAP'){group='Chủ sạp';owner=1;location=1}
    else if(role==='VI'){group='Vị trí tiền';owner=0;location=1}
    else {group=prompt('Nhóm:','Khác')||'Khác'; owner=confirm('Là chủ sở hữu/công nợ?')?1:0; location=confirm('Là vị trí/ví tiền?')?1:0}
    const row={code,name,group,owner,location};
    const {data:ins,error}=await supa.from('parties').insert(toPartyDb(row)).select().single();if(error)throw error;
    data.parties.push(fromPartyDb(ins));renderAll()
  }catch(e){msg(e.message||String(e),'err')}
}

async function patchParty(id,field,val){const row=data.parties.find(p=>p.id===id);if(!row)return;row[field]=val;renderAll();try{await requireLogin();const {error}=await supa.from('parties').update(toPartyDb(row)).eq('id',id);if(error)throw error}catch(e){msg(e.message||String(e),'err')}}
async function delParty(id){if(!confirm('Xoá đối tượng? Không nên xoá nếu đã dùng.'))return;try{await requireLogin();const {error}=await supa.from('parties').delete().eq('id',id);if(error)throw error;data.parties=data.parties.filter(x=>x.id!==id);renderAll()}catch(e){msg(e.message||String(e),'err')}}
function exportData(){const blob=new Blob([JSON.stringify(data,null,2)],{type:'application/json'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='backup-quy-supabase.json';a.click();URL.revokeObjectURL(a.href)}

function withId(row,id){if(id)row.id=id;return row}
function normalizeBackupObject(im){
  im=im||{};
  im.parties=im.parties||[]; im.sales=im.sales||[]; im.flows=im.flows||[]; im.lots=im.lots||[]; im.lotItems=im.lotItems||[]; im.lotCosts=im.lotCosts||[];
  for(const f of im.flows){
    if(f.type==='Phải thu đầu kỳ'){
      f.owner='QUANG';
      if(!f.from&&f.to)f.from=f.to;
    }
  }
  return im;
}
async function upsertPartiesByCode(parties){
  let inserted=0, updated=0;
  const existing=new Map((data.parties||[]).map(p=>[String(p.code||'').toUpperCase(),p]));
  for(const p of parties){
    const code=String(p.code||'').toUpperCase();
    if(!code)continue;
    const row=toPartyDb({code,name:p.name||code,group:p.group||'',owner:p.owner,location:p.location,note:p.note});
    const ex=existing.get(code);
    if(ex){
      const {error}=await supa.from('parties').update(row).eq('id',ex.id);
      if(error)throw error;
      updated++;
    }else{
      const {data:ins,error}=await supa.from('parties').insert(row).select().single();
      if(error)throw error;
      if(ins)existing.set(code,fromPartyDb(ins));
      inserted++;
    }
  }
  return {inserted,updated};
}
async function upsertRows(table,rows,mapper){
  if(!rows||!rows.length)return 0;
  const payload=rows.map(x=>withId(mapper(x),x.id));
  const {error}=await supa.from(table).upsert(payload,{onConflict:'id'});
  if(error)throw error;
  return payload.length;
}

async function importData(e){
  const file=e.target.files[0]; if(!file)return;
  const reader=new FileReader();
  reader.onload=async()=>{
    try{
      await requireLogin();
      await syncAll();
      const im=normalizeBackupObject(JSON.parse(reader.result));
      const ok=confirm('Nhập backup vào Supabase theo chế độ CẬP NHẬT/CHỐNG TRÙNG?\n\n- Danh mục: trùng mã thì cập nhật, chưa có thì thêm\n- Dòng tiền/lô: trùng id thì cập nhật, chưa có thì thêm\n- Không xoá dữ liệu hiện có\n\nTiếp tục?');
      if(!ok)return;
      const partyResult=await upsertPartiesByCode(im.parties);
      const salesCount=await upsertRows('sales',im.sales,toSaleDb);
      const flowCount=await upsertRows('flows',im.flows,toFlowDb);
      const lotCount=await upsertRows('lots',im.lots,toLotDb);
      let itemCount=0,costCount=0;
      try{
        itemCount=await upsertRows('lot_items',im.lotItems,toItemDb);
        costCount=await upsertRows('lot_costs',im.lotCosts,toCostDb);
      }catch(extraErr){
        msg('Đã nhập danh mục/tiền/lô. Lot items/costs chưa nhập được: '+(extraErr.message||extraErr),'err');
      }
      msg(`Nhập JSON xong: danh mục cập nhật ${partyResult.updated}, thêm ${partyResult.inserted}; sales ${salesCount}; flows ${flowCount}; lots ${lotCount}; items ${itemCount}; costs ${costCount}.`);
      await syncAll();
    }catch(err){msg(err.message||String(err),'err')}
    finally{e.target.value=''}
  };
  reader.readAsText(file);
}

