/* V16.7 - desktop lô hàng compact overview, mobile untouched */
function qdLotIsSoldDone(l){
  return !!(l && (l.saleLocked || l.soldAt || n(l.saleCny) || n(l.saleVnd) || n(l.saleTotal)));
}
function qdDesktopLotInfo(l){
  if(!l)return {rank:99,label:'Chưa rõ',cls:'qd-stage-new'};
  if(qdLotIsSoldDone(l)) return {rank:90,label:'Đã bán',cls:'qd-stage-sold'};
  if(l.sellingAt) return {rank:10,label:'Đang bán',cls:'qd-stage-selling'};
  if(l.cnArriveAt) return {rank:20,label:'Đang ở chợ',cls:'qd-stage-market'};
  if(l.unloadAt||l.cnTransferAt) return {rank:30,label:'Đang lên chợ',cls:'qd-stage-road'};
  if(l.borderAt||l.cnCrossAt) return {rank:40,label:'Ở khẩu TQ',cls:'qd-stage-border-cn'};
  if(l.inspectionAt||l.postcheckType||l.coAt||l.quarantineAt) return {rank:50,label:'Khẩu VN/thủ tục',cls:'qd-stage-border-vn'};
  if(l.resultAt||l.sampleAt) return {rank:60,label:'Chờ thủ tục',cls:'qd-stage-procedure'};
  if(l.vnDepartAt) return {rank:70,label:'Xe đang chạy',cls:'qd-stage-procedure'};
  return {rank:80,label:'Mới nhập',cls:'qd-stage-new'};
}
function qdDesktopSortLots(rows){
  return [...(rows||[])].sort((a,b)=>{
    const ia=qdDesktopLotInfo(a), ib=qdDesktopLotInfo(b);
    if(ia.rank!==ib.rank)return ia.rank-ib.rank;
    const da=qdDesktopLastDate(a), db=qdDesktopLastDate(b);
    if(db!==da)return db-da;
    return String(b.code||'').localeCompare(String(a.code||''));
  });
}
function qdDesktopSidebarLots(rows){
  const active=(rows||[]).filter(l=>qdDesktopLotInfo(l).rank<90);
  return (active.length?active:(rows||[])).slice(0,60);
}
