/* V16.11 - desktop lot overview: điểm bán thật + chi tiết lô cuộn đủ */
function qdV1611CleanText(x){return String(x||'').trim().replace(/\s+/g,' ')}
function qdV1611Strip(x){return qdV1611CleanText(x).toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'')}
function qdDesktopLotSalePoint(l){
  if(!l)return '';
  const badWords=new Set([
    'dang ban','da ban','dang o cho','dang len cho','o khau tq','khau tq','khau vn/thu tuc',
    'xe dang chay','cho thu tuc','moi nhap','chua ro','dang theo doi','da toi cho','bo hang/sang xe'
  ]);
  const stage=qdV1611Strip((qdDesktopLotInfo(l)||{}).label);
  const owner=qdV1611Strip(pname(l.owner));
  function isBad(v){
    const s=qdV1611CleanText(v), b=qdV1611Strip(v);
    if(!s)return true;
    if(badWords.has(b))return true;
    if(stage && b===stage)return true;
    if(owner && b===owner)return true;
    // Không lấy tên đối tượng/chủ sạp kiểu "CHỦ SẠP QUẢNG CHÂU" làm điểm bán,
    // nhưng vẫn cho phép điểm bán thật trùng tên chợ như "TRỊNH CHÂU".
    if(b.includes('chu sap')||b.includes('chủ sạp'))return true;
    if(b.includes('dang ban')||b.includes('da ban')||b.includes('dang o cho')||b.includes('dang len cho'))return true;
    return false;
  }
  // Ưu tiên các trường điểm bán/chợ thật đang dùng trong form chi tiết lô.
  const vals=[
    l.cnMarket,l.market,l.salePoint,l.sellPoint,l.destinationMarket,l.sellMarket,l.saleMarket,
    l.marketPoint,l.sell_place,l.marketName,l.destination,l.cnDestination
  ].map(qdV1611CleanText).filter(Boolean);
  return vals.find(v=>!isBad(v))||'';
}
