    let left=Math.min(Math.max(12,r.left),window.innerWidth-w-12);
    let top=r.bottom+10;
    if(top+h>window.innerHeight-12)top=Math.max(12,r.top-h-10);
    el.style.left=left+'px';el.style.top=top+'px';el.style.visibility='visible';
