      f+=qfield('Số tiền',money('ex_amount','Số tiền bù/trả'));
      f+=qfield('Người thụ hưởng','<input id="ex_receiver" placeholder="Để trống = đối tác">');
      f+=qfield('Ghi chú',note('ex_note','Tôi bù/trả lại đối tác'));
