    t=t.replace(/\bCN_TEMP\s*:\s*[\d.]+/ig,'').replace(/\bCN_VENT\s*:\s*[\d.]+/ig,'').replace(/\bTEMP\s*:\s*[\d.]+/ig,'').replace(/\bVENT\s*:\s*[\d.]+/ig,'');
    t=t.replace(/\s*\\n\s*/g,' · ').replace(/\s{2,}/g,' ').replace(/\s*·\s*·\s*/g,' · ').trim();
