// extracted from <script id="qd-v17-mobile-detail-scroll-safe-js">
(function(){
  function isMobile(){return window.innerWidth<=760}
  function activeTab(){try{return typeof activeTabId==='function'?activeTabId():''}catch(_){return ''}}
  function inLotDetail(){return isMobile() && activeTab()==='lots' && !!(window.qdMobileDetailId||window.qdForceLotDetailId||window.mobileLotViewMode==='detail')}
  function currentLotId(){try{return String(window.qdMobileDetailId||window.qdForceLotDetailId||selectedLotId||'')}catch(_){return String(window.qdMobileDetailId||window.qdForceLotDetailId||'')}}
  function saveScroll(){
    if(!inLotDetail())return null;
    return {id:currentLotId(), y:window.scrollY||document.documentElement.scrollTop||0, t:Date.now()};
  }
  function restoreScroll(s){
    if(!s||!inLotDetail())return;
    if(currentLotId()!==s.id)return;
    if(window.qdOpenLotScrollTopUntil && Date.now()<window.qdOpenLotScrollTopUntil)return;
    setTimeout(function(){try{window.scrollTo(0,s.y)}catch(_){}},40);
    setTimeout(function(){try{window.scrollTo(0,s.y)}catch(_){}},140);
  }
  function markNewOpen(){window.qdOpenLotScrollTopUntil=Date.now()+900}
  ['openLotDetail','openLotFromDashboard','qdMOpenLot','qdOpenExactLotDetail'].forEach(function(name){
    var old=window[name];
    if(typeof old==='function'&&!old.qdScrollSafeWrapped){
      var wrapped=function(){markNewOpen(); return old.apply(this,arguments)};
      wrapped.qdScrollSafeWrapped=true;
      window[name]=wrapped;
      try{ if(name==='openLotDetail') openLotDetail=wrapped; if(name==='openLotFromDashboard') openLotFromDashboard=wrapped; if(name==='qdMOpenLot') qdMOpenLot=wrapped; }catch(_){ }
    }
  });
  ['renderLotsMobile','renderLots','renderAll','refreshVisible'].forEach(function(name){
    var old=window[name];
    if(typeof old==='function'&&!old.qdKeepScrollWrapped){
      var wrapped=function(){var s=saveScroll(); var r=old.apply(this,arguments); restoreScroll(s); return r};
      wrapped.qdKeepScrollWrapped=true;
      window[name]=wrapped;
      try{ if(name==='renderLotsMobile') renderLotsMobile=wrapped; if(name==='renderLots') renderLots=wrapped; if(name==='renderAll') renderAll=wrapped; if(name==='refreshVisible') refreshVisible=wrapped; }catch(_){ }
    }
  });
})();

// extracted from <script id="qd-v17-final-mobile-detail-safety">
(function(){
  if(window.qdV17FinalMobileDetailSafety) return;
  window.qdV17FinalMobileDetailSafety = true;

  function isMobile(){ return window.innerWidth <= 760 || (typeof window.isM === 'function' && window.isM()); }
  function currentTab(){ try{ return typeof activeTabId === 'function' ? activeTabId() : ''; }catch(e){ return ''; } }
  function setLot(id){
    try{ selectedLotId = id; }catch(e){}
    window.qdMobileDetailId = id;
    window.qdForceLotDetailId = id;
    window.desktopLotViewMode = 'detail';
    window.mobileLotViewMode = 'detail';
  }
  function openExact(id){
    if(!id) return;
    window.qdOpenLotScrollTopUntil = Date.now() + 900;
    setLot(id);
    try{ if(typeof qdMCloseDrawer === 'function') qdMCloseDrawer(); }catch(e){}
    try{ if(typeof showTab === 'function') showTab('lots'); }catch(e){}
    setTimeout(function(){
      setLot(id);
      try{ if(typeof renderLots === 'function') renderLots(); }
      catch(e){ try{ if(typeof msg === 'function') msg('Lỗi mở chi tiết lô: ' + (e.message || e), 'err'); }catch(_){} }
      setTimeout(function(){ try{ window.scrollTo(0,0); }catch(e){} },30);
    },60);
  }
  ['openLotDetail','openLotFromDashboard','qdMOpenLot'].forEach(function(name){
    window[name] = openExact;
    try{
      if(name === 'openLotDetail') openLotDetail = openExact;
      if(name === 'openLotFromDashboard') openLotFromDashboard = openExact;
      if(name === 'qdMOpenLot') qdMOpenLot = openExact;
    }catch(e){}
  });

  function shouldKeepScroll(){
    if(!isMobile()) return false;
    if(currentTab() !== 'lots') return false;
    if(!(window.qdMobileDetailId || window.qdForceLotDetailId || window.mobileLotViewMode === 'detail')) return false;
    if(window.qdOpenLotScrollTopUntil && Date.now() < window.qdOpenLotScrollTopUntil) return false;
    return true;
  }
  function wrapKeepScroll(fnName){
    var old = window[fnName];
    if(typeof old !== 'function' || old.qdKeepMobileScroll2) return;
    var wrapped = function(){
      var keep = shouldKeepScroll();
      var y = keep ? (window.scrollY || document.documentElement.scrollTop || 0) : 0;
      var r = old.apply(this, arguments);
      if(keep){
        setTimeout(function(){ try{ window.scrollTo(0,y); }catch(e){} }, 40);
        setTimeout(function(){ try{ window.scrollTo(0,y); }catch(e){} }, 160);
      }
      return r;
    };
    wrapped.qdKeepMobileScroll2 = true;
    window[fnName] = wrapped;
    try{
      if(fnName === 'renderLots') renderLots = wrapped;
      if(fnName === 'renderLotsMobile') renderLotsMobile = wrapped;
      if(fnName === 'refreshVisible') refreshVisible = wrapped;
      if(fnName === 'renderAll') renderAll = wrapped;
    }catch(e){}
  }
  ['renderLots','renderLotsMobile','refreshVisible','renderAll'].forEach(wrapKeepScroll);
})();

