// extracted from <script id="qd-v18-business-js">
(function(){
  if(window.qdV18Installed)return; window.qdV18Installed=true;
  const esc = x=>{try{return escHtml(x)}catch(_){return String(x??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]))}};
  const num = x=>{try{return n(x)}catch(_){const v=Number(String(x||'').replace(/[^0-9.-]/g,''));return isFinite(v)?v:0}};
  const fm = (a,c)=>{try{return fmt(a,c)}catch(_){return (num(a)).toLocaleString('vi-VN')+(c?' '+c:'')}};
  const name = c=>{try{return pname(c)}catch(_){return c||''}};
  const today = ()=>{try{return todayStr()}catch(_){return new Date().toISOString().slice(0,10)}};
  function noteGet(l,k){try{return lotNoteExtraGet(l,k)}catch(_){const m=String(l&&l.note||'').match(new RegExp('(?:^|\\n)'+k+':([^\\n]*)'));return m?m[1].trim():''}}
  function noteSet(l,k,v){try{return lotNoteExtraSet(l,k,v)}catch(_){let note=String(l.note||'').replace(new RegExp('(?:^|\\n)'+k+':[^\\n]*','g'),'').trim(); if(String(v||'').trim()) note=(note?note+'\\n':'')+k+':'+String(v||'').trim(); l.note=note;}}
  const TYPE_KEY='LOAI_LO';
  const TYPES={
    customs:{label:'Chỉ thông quan',short:'Thông quan',hint:'Lấy chênh lệch luật; vẫn có list hàng, BKS VN, đầu/mooc TQ.'},
    full:{label:'Thông quan + bán hộ',short:'TQ + bán hộ',hint:'Đầy đủ thông quan, xe, chợ, list hàng, tiền bán.'},
    border:{label:'Nhận bán hộ tại khẩu TQ',short:'Nhận tại khẩu',hint:'Vẫn nhập BKS VN để đối soát, thêm đầu/mooc TQ và chợ.'}
  };
  function lotType(l){return noteGet(l,TYPE_KEY)||'full'}
  function typeLabel(l){return (TYPES[lotType(l)]||TYPES.full).label}
  function typeShort(l){return (TYPES[lotType(l)]||TYPES.full).short}
  window.qdV18LotType=lotType;
  window.qdV18TypeLabel=typeLabel;

  function prefixForOwner(owner){
    const p=(window.data&&data.parties||[]).find(x=>String(x.code||'')===String(owner||''));
    let raw=String((p&&p.code)||owner||(p&&p.name)||'LO').toUpperCase();
    try{raw=stripText(raw).toUpperCase()}catch(_){}
    raw=raw.replace(/[^A-Z0-9]/g,'');
    return raw.slice(0,10)||'LO';
  }
  function nextCode(owner,ignoreId=''){
    const p=prefixForOwner(owner); let max=0;
    (window.data&&data.lots||[]).forEach(l=>{
      if(ignoreId&&String(l.id)===String(ignoreId))return;
      const c=String(l.code||'').toUpperCase();
      let m=c.match(new RegExp('^'+p+'-(\\d+)$')) || c.match(new RegExp('^'+p+'-20\\d{2}-(\\d+)$')) || c.match(new RegExp('^'+p+'-\\d{6}-(\\d+)$'));
      if(m)max=Math.max(max,Number(m[1]||0));
    });
    return p+'-'+(max+1);
  }
  function tempCode(){return nextCode('LO')}
  function autoCode(code,owner){
    const c=String(code||'').toUpperCase(); if(!c||c.startsWith('NHAP-'))return true;
    if(/^[A-Z0-9]+-\d+$/.test(c))return true;
    if(/^[A-Z0-9]+-20\d{2}-\d+$/.test(c))return true;
    if(owner&&c.startsWith(prefixForOwner(owner)+'-'))return true;
    return false;
  }
  try{window.nextOwnerLotCode=nextCode; nextOwnerLotCode=nextCode;}catch(_){}
  try{window.tempLotCode=tempCode; tempLotCode=tempCode;}catch(_){}
  try{window.isAutoLotCode=autoCode; isAutoLotCode=autoCode;}catch(_){}

  function optsList(list,val='',blank=true){return (blank?'<option value=""></option>':'')+(list||[]).map(p=>`<option value="${esc(p.code)}" ${String(p.code)===String(val)?'selected':''}>${esc((p.name||p.code)+' - '+p.code)}</option>`).join('')}
  function partiesBy(words){
    const arr=(window.data&&data.parties||[]).filter(p=>{
      const s=String((p.group||'')+' '+(p.name||'')+' '+(p.code||'')).toLowerCase();
      return words.some(w=>s.includes(w));
    });
    return arr.length?arr:(window.data&&data.parties||[]);
  }
  function ownersOpt(v=''){let arr=[];try{arr=salesOwners()}catch(_){arr=(window.data&&data.parties)||[]} return optsList(arr,v,true)}
  function stallsOpt(v=''){let arr=[];try{arr=stalls()}catch(_){arr=partiesBy(['sạp','sap','chợ','cho'])} return optsList(arr,v,true)}
  function lawOpt(v=''){return optsList(partiesBy(['luật','luat','law','付汇']),v,true)}
  function truckOwnerOpt(v=''){return optsList(partiesBy(['xe','truck','chủ xe','chu xe','ncc','nhà cung cấp']),v,true)}
  function field(label,html,cls=''){return `<div class="qd-v18-field ${cls}"><label>${label}</label>${html}</div>`}
  function refreshNewLotType(){
    const t=document.getElementById('v18_type')?.value||'full';
    document.querySelectorAll('.qd-v18-type').forEach(b=>b.classList.toggle('active',b.dataset.type===t));
    document.querySelectorAll('[data-show]').forEach(el=>{
      const show=String(el.dataset.show||'').split(',').includes(t);
      el.classList.toggle('qd-v18-hide',!show);
    });
    const hint=document.getElementById('v18_type_hint'); if(hint)hint.textContent=(TYPES[t]||TYPES.full).hint;
  }
  window.qdV18PickType=function(t){const el=document.getElementById('v18_type'); if(el){el.value=t; refreshNewLotType();}}
  window.qdV18CloseNewLot=function(){document.getElementById('qdV18NewLotMask')?.remove()}
  window.qdV18ShowNewLot=function(){
    document.getElementById('qdV18NewLotMask')?.remove();
    const div=document.createElement('div'); div.id='qdV18NewLotMask'; div.className='qd-v18-modal-mask';
    div.innerHTML=`<div class="qd-v18-modal"><div class="qd-v18-modal-head"><div><h2>QuangDurenOnline V18 · Lô mới</h2><p>Chọn loại nghiệp vụ trước, app chỉ lấy thông tin cần thiết. Mã lô mới theo dạng <b>MÃKH-1</b>, <b>MÃKH-2</b>...</p></div><button class="qd-v18-x" onclick="qdV18CloseNewLot()">×</button></div><div class="qd-v18-body">
      <input id="v18_type" type="hidden" value="full">
      <div class="qd-v18-type-grid">${Object.entries(TYPES).map(([k,t])=>`<button class="qd-v18-type ${k==='full'?'active':''}" data-type="${k}" onclick="qdV18PickType('${k}')"><b>${esc(t.label)}</b><span>${esc(t.hint)}</span></button>`).join('')}</div>
      <div id="v18_type_hint" class="qd-v18-hint">${esc(TYPES.full.hint)}</div>
      <div class="qd-v18-grid">
        ${field('Chủ hàng',`<select id="v18_owner" onchange="qdV18PreviewCode()">${ownersOpt()}</select>`)}
        ${field('Mã lô tự nhảy',`<input id="v18_code" placeholder="Chọn chủ hàng để tự tạo, VD RTH-1">`)}
        ${field('BKS Việt Nam đối soát',`<input id="v18_truck" placeholder="77C15904 / 48H01816...">`)}
        ${field('Mooc VN',`<input id="v18_mooc" placeholder="nếu có">`)}
        ${field('Đầu xe TQ',`<input id="v18_cnTruck" placeholder="đầu xe TQ nếu có">`)}
        ${field('Mooc xe TQ',`<input id="v18_cnMooc" placeholder="JK373 / H34P...">`)}
        ${field('Chợ / điểm bán TQ',`<input id="v18_cnMarket" placeholder="TRỊNH CHÂU / Quảng Châu...">`)}
        ${field('Chủ sạp/chợ',`<select id="v18_stall">${stallsOpt()}</select>`,'',)}
        ${field('Nhà luật',`<select id="v18_law">${lawOpt()}</select>`)}
        ${field('Chủ xe / NCC xe',`<select id="v18_truckOwner">${truckOwnerOpt()}</select>`,'v18-only-full')}
        ${field('Cửa khẩu',`<input id="v18_borderGate" placeholder="Hữu Nghị / Tân Thanh...">`)}
        ${field('Mác / thương hiệu TQ',`<input id="v18_brand" placeholder="中华龙 / 天山海...">`)}
        ${field('Ghi chú',`<input id="v18_note" placeholder="ghi chú ngắn">`)}
      </div>
      <div class="qd-v18-actions"><button class="primary" onclick="qdV18CreateLot()">Tạo lô V18</button><button onclick="qdV18CloseNewLot()">Huỷ</button></div>
    </div></div>`;
    document.body.appendChild(div);
    setTimeout(()=>{refreshNewLotType(); qdV18PreviewCode();},0);
  }
  window.qdV18PreviewCode=function(){const owner=document.getElementById('v18_owner')?.value||''; const el=document.getElementById('v18_code'); if(el&&!el.value&&owner)el.value=nextCode(owner)}
  window.addLot=window.qdV18ShowNewLot; try{addLot=window.qdV18ShowNewLot}catch(_){}
  window.qdV18CreateLot=async function(){
    try{
      await requireLogin();
      const type=document.getElementById('v18_type')?.value||'full';
      const owner=document.getElementById('v18_owner')?.value||'';
      if(!owner){alert('Chọn chủ hàng trước để tự nhảy mã lô.');return}
      const code=(document.getElementById('v18_code')?.value||nextCode(owner)).trim().toUpperCase();
      const dup=(data.lots||[]).find(l=>String(l.code||'').toUpperCase()===code); if(dup){alert('Mã lô '+code+' đã tồn tại.');return}
      const row={code,date:today(),owner,stall:document.getElementById('v18_stall')?.value||'',currency:'CNY',status:'Đang theo dõi',market:'',brandCn:document.getElementById('v18_brand')?.value||'',factoryDate:'',cnTransferAt:'',cnTruck:document.getElementById('v18_cnTruck')?.value||'',cnMooc:document.getElementById('v18_cnMooc')?.value||'',truck:document.getElementById('v18_truck')?.value||'',mooc:document.getElementById('v18_mooc')?.value||'',containerNo:'',driverPhone:'',truckOwner:document.getElementById('v18_truckOwner')?.value||'',vnFrom:'',borderGate:document.getElementById('v18_borderGate')?.value||'',vnLaw:document.getElementById('v18_law')?.value||'',vnDepartAt:'',vnCheckAt:'',temp:'',vent:'',vnFreight:0,layoverFee:0,plugFee:0,cnCrossAt:'',cnReceiver:'',cnMarket:(document.getElementById('v18_cnMarket')?.value||'').toUpperCase(),cnArriveAt:'',cnCondition:'',cnYardFee:0,cnTransferFee:0,cnWorkerFee:0,slotFee:0,cnLawFee:0,saleTotal:0,saleCny:0,saleVnd:0,saleRateRef:0,saleLocked:false,commission:0,costCharge:0,costActual:0,compensation:0,sampleAt:'',resultAt:'',quarantineAt:'',coAt:'',borderAt:'',inspectionAt:'',postcheckType:'',unloadAt:'',sellingAt:'',soldAt:'',growCode:'',packCode:'',note:document.getElementById('v18_note')?.value||''};
      noteSet(row,TYPE_KEY,type); noteSet(row,'DATA_YEAR',String(new Date(row.date).getFullYear()||new Date().getFullYear()));
      const {data:ins,error}=await supa.from('lots').insert(toLotDb(row)).select().single(); if(error)throw error;
      const lot=fromLotDb(ins); data.lots=data.lots.filter(x=>x.id!==lot.id); data.lots.unshift(lot); selectedLotId=lot.id; window.qdMobileDetailId=lot.id; window.desktopLotViewMode='detail'; try{lotEditState[lotEditKey(lot.id)]=false}catch(_){}
      qdV18CloseNewLot(); msg('Đã tạo lô V18: '+lot.code+' · '+typeLabel(lot)); showTab('lots'); setTimeout(()=>{selectedLotId=lot.id;window.qdMobileDetailId=lot.id;try{renderLots()}catch(_){}},50);
    }catch(e){msg(e.message||String(e),'err')}
  }

  function itemRows(l){let rows=[];try{rows=lotItems(l.id)||[]}catch(_){rows=(data.lotItems||[]).filter(x=>String(x.lotId)===String(l.id))}return rows}
  function cnVariety(x){const v=String(x.variety||''); if(/[\u4e00-\u9fff]/.test(v))return v; if(/ri6|干尧/i.test(v))return '干尧'; if(/month|mon|dona|金枕/i.test(v))return '金枕'; return v||'—'}
  function compactItemsHtml(l){
    const rows=itemRows(l); let tb=''; let totalBox=0,totalKg=0;
    rows.forEach((x,i)=>{totalBox+=num(x.boxes); totalKg+=num(x.totalKg); tb+=`<tr><td>${esc(cnVariety(x))}</td><td>${esc(x.grade||'')}</td><td>${esc((x.spec||x.kgPerBox||'')?String(x.spec||x.kgPerBox).replace(/kg$/i,'')+'kg':'')}</td><td>${fm(num(x.boxes),'')}</td><td>${fm(num(x.totalKg),'kg').replace(' kg','kg')}</td><td>${esc(x.bandColor||x.source||'')}</td><td>${esc(x.note||'')}</td></tr>`});
    if(!tb)tb='<tr><td colspan="7" style="text-align:center;color:#94a3b8;font-weight:800">Chưa nhập list hàng.</td></tr>';
    return `<div class="qd-v18-cn-table-wrap"><table class="qd-v18-cn-table"><thead><tr><th>主种类</th><th>品级</th><th>规格</th><th>件数</th><th>重量</th><th>记号/带</th><th>备注</th></tr></thead><tbody>${tb}</tbody></table></div><div class="qd-v18-totals"><span>合计 / Tổng kiện: ${fm(totalBox,'')}</span><span>总重量 / Tổng kg: ${fm(totalKg,'kg')}</span><span>市场 / Chợ: ${esc(l.cnMarket||l.market||name(l.stall)||'—')}</span></div>`;
  }
  function v18MobileDetail(l){
    const edit=window.qdV18EditLotId===l.id;
    const missing=[]; if(!l.truck)missing.push('BKS VN'); if(!l.cnMooc)missing.push('Mooc TQ'); if(!l.cnTruck&&lotType(l)!=='border')missing.push('Đầu xe TQ'); if(!l.cnMarket&&!l.market)missing.push('Chợ/điểm bán'); if(!l.vnLaw&&(lotType(l)==='customs'||lotType(l)==='full'))missing.push('Nhà luật');
    return `<div class="qd-m-lots-page qd-v18-mobile-detail"><div class="qd-m-detail-head"><button class="qd-m-back" onclick="qdMBackLots&&qdMBackLots()">← Bảng nhanh</button><button class="primary" onclick="addLot()">+ Lô mới</button></div>
      <div class="qd-v18-quick-card"><div class="qd-v18-quick-head"><div><h2>${esc(l.code||'Lô mới')}</h2><div class="qd-v18-quick-sub">${esc(name(l.owner)||'Chưa chủ hàng')} · ${esc(l.truck||'chưa BKS VN')} · ${esc(l.cnMooc||'chưa mooc TQ')}</div></div><span class="qd-v18-type-pill">${esc(typeShort(l))}</span></div>
      ${missing.length?`<div class="qd-v18-hint">Còn thiếu: ${missing.map(esc).join(', ')}</div>`:''}
      <div class="qd-v18-kv"><span>Chủ hàng</span><b>${esc(name(l.owner)||'—')}</b><span>BKS VN</span><b>${esc(l.truck||'—')}</b><span>Đầu/Mooc TQ</span><b>${esc([l.cnTruck,l.cnMooc].filter(Boolean).join(' · ')||'—')}</b><span>Chợ/điểm bán</span><b>${esc(l.cnMarket||l.market||name(l.stall)||'—')}</b><span>Nhà luật</span><b>${esc(name(l.vnLaw)||l.vnLaw||'—')}</b><span>Chủ xe</span><b>${esc(name(l.truckOwner)||l.truckOwner||'—')}</b></div></div>
      <div class="qd-v18-quick-card"><div class="qd-v18-quick-head"><h2>发货清单 / List hàng</h2><span class="qd-v18-type-pill">1 màn hình</span></div>${compactItemsHtml(l)}<div class="qd-v18-quick-actions"><button onclick="window.qdV18EditLotId='${esc(l.id)}';renderLots()">Sửa thông tin</button><button onclick="addLotItem('${esc(l.id)}')">+ Hàng</button><button onclick="addLotCost('${esc(l.id)}')">+ Chi phí dịch vụ</button><button onclick="window.qdV18EditLotId='${esc(l.id)}';renderLots();setTimeout(()=>document.querySelector('.qd-v18-edit-box')?.scrollIntoView({behavior:'smooth'}),80)">Mở full</button></div></div>
      ${edit?`<div class="qd-v18-edit-box">${renderLotDetailMobile(l)}</div>`:''}
    </div>`;
  }
  const oldRenderLotsMobile=window.renderLotsMobile;
  if(typeof oldRenderLotsMobile==='function'){
    window.renderLotsMobile=function(){
      try{
        const el=document.getElementById('lots'); if(!el)return;
        const detailId=window.qdMobileDetailId||''; const detail=detailId&&typeof lotById==='function'?lotById(detailId):null;
        if(detail){el.innerHTML=v18MobileDetail(detail); return;}
      }catch(e){try{msg('Lỗi chi tiết V18: '+(e.message||e),'err')}catch(_){}}
      return oldRenderLotsMobile.apply(this,arguments);
    };
    try{renderLotsMobile=window.renderLotsMobile}catch(_){}
  }

  const oldRenderLotDetail=window.renderLotDetail;
  if(typeof oldRenderLotDetail==='function'){
    window.renderLotDetail=function(l){
      const html=oldRenderLotDetail.apply(this,arguments);
      return html;
    };
    try{renderLotDetail=window.renderLotDetail}catch(_){}
  }

  // remove old mobile footer nav permanently
  function killNav(){document.querySelectorAll('.v164-bottom-nav,.mobile-bottom-nav,.bottom-nav,[class*="bottom-nav"],[class*="footer-nav"]').forEach(el=>el.remove())}
  window.qdV164EnsureNav=function(){killNav()}; window.qdV164SetNav=function(){killNav()};
  document.addEventListener('DOMContentLoaded',killNav); setInterval(killNav,1200);
  try{document.title='QuangDurenOnline V18'}catch(_){}
})();

// extracted from <script id="qd-v18-2-one-screen-mobile-list-js">
(function(){
  if(window.qdV182OneScreenMobileList)return; window.qdV182OneScreenMobileList=true;
  function E(x){try{return escHtml(x)}catch(_){return String(x??'').replace(/[&<>"']/g,function(m){return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]})}}
  function N(x){try{return n(x)}catch(_){var v=Number(String(x||'').replace(/[^0-9.-]/g,''));return isFinite(v)?v:0}}
  function F(x,cur){try{return fmt(x,cur)}catch(_){return N(x).toLocaleString('vi-VN')+(cur?' '+cur:'')}}
  function PN(x){try{return pname(x)}catch(_){return x||''}}
  function lot(id){try{return lotById(id)}catch(_){return (window.data&&data.lots||[]).find(function(l){return String(l.id)===String(id)})}}
  function items(l){try{return lotItems(l.id)||[]}catch(_){return (window.data&&data.lotItems||[]).filter(function(x){return String(x.lotId)===String(l.id)})}}
  function noteGet(l,k){try{return lotNoteExtraGet(l,k)}catch(_){var m=String(l&&l.note||'').match(new RegExp('(?:^|\\n)'+k+':([^\\n]*)'));return m?m[1].trim():''}}
  function ltype(l){try{return window.qdV18LotType?window.qdV18LotType(l):(noteGet(l,'LOAI_LO')||'full')}catch(_){return 'full'}}
  function typeShort(l){var t=ltype(l);return t==='customs'?'Thông quan':t==='border'?'Nhận tại khẩu':'TQ + bán hộ'}
  function cnVar(x){var v=String(x&&x.variety||'').trim(); if(/[\u4e00-\u9fff]/.test(v))return v; if(/ri6|干尧/i.test(v))return '干尧'; if(/month|mon|dona|金枕/i.test(v))return '金枕'; return v||'—'}
  function spec(x){var s=String(x&&x.spec||'').trim();var k=String(x&&x.kgPerBox||'').trim();var o=s||k;if(!o)return '—';return /kg$/i.test(o)?o:o+'kg'}
  function sign(x){try{if(x.markText)return x.markText;if(typeof extractMark==='function'){var m=extractMark(x.note);if(m)return m}}catch(_){}return x.bandColor||x.source||'—'}
  function remark(x){return x.remark||x.note||''}
  function cnGrid(l){
    var rows=items(l), box=0, kg=0;
    var html='<div class="qd-v18-cn-sheet"><div class="qd-v18-cn-title"><h2>发货清单 / List hàng</h2><span>1 màn hình</span></div><div class="qd-v18-cn-grid">'+
      '<div class="h">主种类</div><div class="h">品级</div><div class="h">规格</div><div class="h">件</div><div class="h">kg</div><div class="h">记号/带</div><div class="h">备注</div>';
    if(rows.length){rows.forEach(function(x){box+=N(x.boxes);kg+=N(x.totalKg);html+=
      '<div class="c main">'+E(cnVar(x))+'</div><div class="c">'+E(x.grade||'—')+'</div><div class="c">'+E(spec(x))+'</div><div class="c num">'+E(F(N(x.boxes),'').replace(/\s/g,''))+'</div><div class="c num">'+E(F(N(x.totalKg),'kg').replace(/ kg/g,'kg'))+'</div><div class="c">'+E(sign(x))+'</div><div class="c note">'+E(remark(x))+'</div>';});}
    else html+='<div class="qd-v18-cn-empty">Chưa nhập list hàng.</div>';
    html+='</div><div class="qd-v18-os-total"><div><span>合计件</span><b>'+E(F(box,'').replace(/\s/g,''))+'</b></div><div><span>总重量</span><b>'+E(F(kg,'kg').replace(/ kg/g,'kg'))+'</b></div><div><span>市场</span><b>'+E(l.cnMarket||l.market||PN(l.stall)||'—')+'</b></div></div></div>';
    return html;
  }
  function detail(l){
    var edit=window.qdV18EditLotId===l.id;
    return '<div class="qd-m-lots-page qd-v18-mobile-detail qd-v18-one-screen-detail">'+
      '<div class="qd-m-detail-head"><button class="qd-m-back" onclick="window.qdMobileDetailId=\'\';window.qdForceLotDetailId=\'\';window.mobileLotViewMode=\'list\';renderLots()">← Bảng nhanh</button><button class="primary" onclick="addLot()">+ Lô mới</button></div>'+
      '<div class="qd-v18-os-card"><div class="qd-v18-os-head"><div><h2>'+E(l.code||'Lô mới')+'</h2><div class="qd-v18-os-sub">'+E(PN(l.owner)||'Chưa chủ hàng')+' · '+E(l.truck||'chưa BKS VN')+' · '+E(l.cnMooc||'chưa mooc TQ')+'</div></div><span class="qd-v18-os-pill">'+E(typeShort(l))+'</span></div>'+
      '<div class="qd-v18-os-meta"><div><span>货主/Chủ hàng</span><b>'+E(PN(l.owner)||'—')+'</b></div><div><span>越南车/BKS VN</span><b>'+E(l.truck||'—')+'</b></div><div><span>中方挂车/Mooc</span><b>'+E(l.cnMooc||'—')+'</b></div><div><span>中方车/Đầu TQ</span><b>'+E(l.cnTruck||'—')+'</b></div><div><span>市场/Chợ</span><b>'+E(l.cnMarket||l.market||PN(l.stall)||'—')+'</b></div><div><span>律师/Nhà luật</span><b>'+E(PN(l.vnLaw)||l.vnLaw||'—')+'</b></div></div></div>'+
      cnGrid(l)+
      '<div class="qd-v18-os-actions"><button onclick="window.qdV18EditLotId=\''+E(l.id)+'\';renderLots();document.querySelector(\'.qd-v18-edit-box\')&&document.querySelector(\'.qd-v18-edit-box\').classList.add(\'qd-open\')">Sửa</button><button onclick="addLotItem(\''+E(l.id)+'\')">+ Hàng</button><button onclick="addLotCost(\''+E(l.id)+'\')">+ Phí DV</button><button onclick="window.qdV18EditLotId=\''+E(l.id)+'\';renderLots();setTimeout(function(){var e=document.querySelector(\'.qd-v18-edit-box\');if(e){e.classList.add(\'qd-open\');e.scrollIntoView({behavior:\'smooth\'})}},80)">Full</button></div>'+
      (edit?'<div class="qd-v18-edit-box qd-open">'+(typeof renderLotDetailMobile==='function'?renderLotDetailMobile(l):'')+'</div>':'')+'</div>';
  }
  var old=window.renderLotsMobile;
  window.renderLotsMobile=function(){
    try{var el=document.getElementById('lots');if(!el)return;var id=window.qdMobileDetailId||window.qdForceLotDetailId||((window.mobileLotViewMode==='detail')?selectedLotId:'');var l=id?lot(id):null;if(l){el.innerHTML=detail(l);return;}}
    catch(e){try{msg('Lỗi chi tiết V18.2: '+(e.message||e),'err')}catch(_){}}
    if(typeof old==='function')return old.apply(this,arguments);
  };
  try{renderLotsMobile=window.renderLotsMobile}catch(_){ }
  function open(id){if(!id)return;try{selectedLotId=id}catch(_){}window.qdMobileDetailId=id;window.qdForceLotDetailId=id;window.mobileLotViewMode='detail';try{if(typeof qdMCloseDrawer==='function')qdMCloseDrawer()}catch(_){};try{showTab('lots')}catch(_){ }setTimeout(function(){try{renderLots()}catch(_){ }},60)}
  window.openLotDetail=open; window.openLotFromDashboard=open; window.qdMOpenLot=open;
  try{openLotDetail=open;openLotFromDashboard=open;qdMOpenLot=open}catch(_){ }
  if(window.innerWidth<=760&&document.getElementById('lots')&&!document.getElementById('lots').classList.contains('hide'))setTimeout(function(){try{renderLotsMobile()}catch(_){ }},80);
})();

