  function noteGet(l,k){try{return lotNoteExtraGet(l,k)}catch(_){var m=String(l&&l.note||'').match(new RegExp('(?:^|\\n)'+k+':([^\\n]*)'));return m?m[1].trim():''}}
  function lotType(l){try{return window.qdV18LotType?window.qdV18LotType(l):(noteGet(l,'LOAI_LO')||'full')}catch(_){return 'full'}}
  function typeShort(l){var t=lotType(l);return t==='customs'?'Thông quan':t==='border'?'Nhận tại khẩu':'TQ + bán hộ'}
  function cnVar(x){var v=String(x&&x.variety||'').trim(); if(/[\u4e00-\u9fff]/.test(v))return v; if(/ri6|干尧/i.test(v))return '干尧'; if(/month|mon|dona|金枕/i.test(v))return '金枕'; return v||'—'}
  function spec(x){var s=String(x&&x.spec||'').trim();var k=String(x&&x.kgPerBox||'').trim();var o=s||k;if(!o)return '—';return /kg$/i.test(o)?o:o+'kg'}
  function sign(x){try{if(x.markText)return x.markText;if(typeof extractMark==='function'){var m=extractMark(x.note);if(m)return m}}catch(_){} return x.bandColor||x.source||'—'}
  function remark(x){return x.remark||x.note||''}

