// extracted from <script id="qd-v18-21-cost-note-align-js">
(function(){
  if(window.qdV1821CostNoteAlign)return;
  window.qdV1821CostNoteAlign=true;

  const BROWSER_TITLE='QuangDurenOnline';
  const HEADER_VERSION='QuangDurenOnline_V19_27_fix_flow_layout_fuhui_logic_clean_3files';
  const INTERNAL_KEYS=['LOAI_LO','DATA_YEAR','LOT_TYPE'];

  function E(x){try{return escHtml(x)}catch(_ ){return String(x??'').replace(/[&<>"']/g,function(m){return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]})}}

  function applyHeader(){
    try{var t=document.querySelector('title'); if(t&&t.textContent!==BROWSER_TITLE)t.textContent=BROWSER_TITLE;}catch(_ ){}
    try{
      var h=document.querySelector('.top h1')||document.querySelector('header h1')||document.querySelector('h1');
      if(h&&h.textContent!==HEADER_VERSION){h.textContent=HEADER_VERSION;h.classList.add('qd-latest-build-title');}
    }catch(_ ){}
  }
  try{Object.defineProperty(document,'title',{configurable:true,get:function(){return BROWSER_TITLE},set:function(_){applyHeader()}})}catch(_ ){}

  function noteText(note){return String(note||'').replace(/\r\n/g,'\n').replace(/\\n/g,'\n')}
  function splitNote(note){
    var internal={}, user=[];
    noteText(note).split(/\n/).forEach(function(line){
      var m=line.match(/^\s*(LOAI_LO|DATA_YEAR|LOT_TYPE)\s*:\s*(.*?)\s*$/i);
      if(m)internal[m[1].toUpperCase()]=m[2];
      else if(line.trim())user.push(line);
    });
    return {internal:internal,user:user.join('\n')};
  }
  function captureInternal(l){
    if(!l)return l;
    var sp=splitNote(l.note);
    l._qdInternal=Object.assign({},l._qdInternal||{},sp.internal);
    l.note=sp.user;
    return l;
  }
  function mergeNote(l){
    var sp=splitNote(l&&l.note);
    var internal=Object.assign({},sp.internal,(l&&l._qdInternal)||{});
    var lines=[];
    var user=(sp.user||'').trim();
    if(user)lines.push(user);
    INTERNAL_KEYS.forEach(function(k){if(internal[k])lines.push(k+':'+internal[k])});
    return lines.join('\n');
  }
  function cleanseLots(){
    try{(data.lots||[]).forEach(captureInternal)}catch(_ ){}
  }
  window.qdV1821CleanseLots=cleanseLots;

  const oldToLotDb=window.toLotDb||(typeof toLotDb==='function'?toLotDb:null);
  if(oldToLotDb&&!oldToLotDb.qdV1821Wrap){
    window.toLotDb=function(l){return oldToLotDb(Object.assign({},l,{note:mergeNote(l)}))};
    window.toLotDb.qdV1821Wrap=true;
    try{toLotDb=window.toLotDb}catch(_ ){}
  }

  function normalizeType(v){
    var s=String(v||'').toLowerCase();
    if(s==='border'||s.includes('khẩu')||s.includes('khau')||s.includes('nhận')||s.includes('nhan'))return 'border';
    if(s==='customs'||s.includes('chỉ')||s.includes('chi thong'))return 'customs';
    return 'full';
  }
  window.qdV18LotType=function(l){captureInternal(l);return normalizeType((l._qdInternal&&l._qdInternal.LOAI_LO)||(l._qdInternal&&l._qdInternal.LOT_TYPE)||'full')};
  window.qdV18TypeLabel=function(l){var t=window.qdV18LotType(l);return t==='border'?'Nhận bán hộ tại khẩu TQ':t==='customs'?'Chỉ thông quan':'Thông quan + bán hộ'};
  window.qdV18TypeShort=function(l){var t=window.qdV18LotType(l);return t==='border'?'Nhận tại khẩu':t==='customs'?'Thông quan':'TQ + bán hộ'};
  try{qdV18LotType=window.qdV18LotType;qdV18TypeLabel=window.qdV18TypeLabel}catch(_ ){}

  function removeV17Panel(){
    try{document.querySelectorAll('#lots #v17-lot-inject,#lots .v17-lot-inject').forEach(function(x){x.remove()})}catch(_ ){}
  }

  window.qdV1821OpenCost=function(){
    try{
      var id=selectedLotId||'';
      if(id)window.qdV17LotId=id;
      showTab('hhcl');
    }catch(e){alert('Chưa mở được sổ chi phí thực: '+(e.message||e))}
  };

  function addCostButton(){
    try{
      var acts=document.querySelector('#lots .qd-v1819-actions')||document.querySelector('#lots .qd-lots-actions');
      if(!acts||acts.querySelector('.qd-v1821-cost-btn'))return;
      var b=document.createElement('button');
      b.type='button';
      b.className='qd-v1821-cost-btn';
      b.textContent='Chi phí thực';
      b.onclick=function(ev){ev.preventDefault();ev.stopPropagation();qdV1821OpenCost()};
      acts.insertBefore(b,acts.firstChild);
    }catch(_ ){}
  }

  function after(){
    cleanseLots();
    removeV17Panel();
    addCostButton();
    applyHeader();
  }

  var oldRenderLots=window.renderLots;
  if(typeof oldRenderLots==='function'&&!oldRenderLots.qdV1821Wrap){
    window.renderLots=function(){cleanseLots();var r=oldRenderLots.apply(this,arguments);setTimeout(after,0);return r};
    window.renderLots.qdV1821Wrap=true;try{renderLots=window.renderLots}catch(_ ){}
  }

  var oldRenderAll=window.renderAll;
  if(typeof oldRenderAll==='function'&&!oldRenderAll.qdV1821Wrap){
    window.renderAll=function(){cleanseLots();var r=oldRenderAll.apply(this,arguments);setTimeout(after,0);return r};
    window.renderAll.qdV1821Wrap=true;try{renderAll=window.renderAll}catch(_ ){}
  }

  var oldRefresh=window.refreshVisible;
  if(typeof oldRefresh==='function'&&!oldRefresh.qdV1821Wrap){
    window.refreshVisible=function(){cleanseLots();var r=oldRefresh.apply(this,arguments);setTimeout(after,0);return r};
    window.refreshVisible.qdV1821Wrap=true;try{refreshVisible=window.refreshVisible}catch(_ ){}
  }

  var oldShowTab=window.showTab;
  if(typeof oldShowTab==='function'&&!oldShowTab.qdV1821Wrap){
    window.showTab=function(){cleanseLots();var r=oldShowTab.apply(this,arguments);setTimeout(after,0);return r};
    window.showTab.qdV1821Wrap=true;try{showTab=window.showTab}catch(_ ){}
  }

  // Nếu panel V17 bị wrapper cũ chèn sau render, observer sẽ xoá ngay để không chiếm layout.
  try{new MutationObserver(function(){removeV17Panel();addCostButton();applyHeader()}).observe(document.getElementById('lots')||document.body,{childList:true,subtree:true})}catch(_ ){}

  cleanseLots();
  after();
  setTimeout(after,50);
  setTimeout(after,500);

  try{window.qdV1821SelfTest={title:BROWSER_TITLE,header:HEADER_VERSION,fix:'hide V17 cost panel, move cost button, clean LOAI_LO/DATA_YEAR from note'};console.log('QD V18.21 self-test',window.qdV1821SelfTest)}catch(_ ){}
})();

