    return '<div class="subcard qd-v1826-list-card" data-v1826-list="'+E(l.id)+'"><div class="subhead"><div class="qd-v1826-list-title"><b>发货清单 / List hàng</b><span>Mặc định 5 dòng · chọn chủng loại dòng trên thì dòng trống bên dưới tự nhận</span></div><div class="inline-actions">'+actions+'</div></div><div class="subbody"><div class="hint">Nhập số kiện/tổng kg cập nhật tổng ngay. Dòng đã sửa tay sẽ không bị ghi đè khi chọn chủng loại ở dòng trên.</div><div class="qd-v1826-total-grid"><div class="qd-v1826-total-card"><span>Tổng kiện/thùng</span><b class="qd-v1826-total-boxes">'+F(total.boxes,'thùng')+'</b></div><div class="qd-v1826-total-card"><span>Tổng kg</span><b class="qd-v1826-total-kg">'+F(total.kg,'kg')+'</b></div><div class="qd-v1826-total-card"><span>Tổng tiền theo list</span><b class="qd-v1826-total-amount">'+F(total.amount,l.currency||'')+'</b></div></div>'+table+'</div></div>';
