// extracted from <script id="qd-v19-0-dong-tien-ui-js">
(function(){
  if(window.qdV190DongTienUi)return; window.qdV190DongTienUi=true;
  var VERSION='QuangDurenOnline_V19_27_fix_flow_layout_fuhui_logic_clean_3files';
  window.qdV19FlowGroup = window.qdV19FlowGroup || 'money';

  function setTitle(){
    try{
      document.title='QuangDurenOnline';
      var h=document.querySelector('.top h1')||document.querySelector('h1');
      if(h)h.textContent=VERSION;
      document.querySelectorAll('.tab').forEach(function(b){
        var oc=b.getAttribute('onclick')||'';
        if(oc.indexOf("showTab('flows'")>=0 || oc.indexOf('showTab("flows"')>=0)b.textContent='Dòng tiền';
      });
    }catch(e){}
  }

  var oldRenderFlows = window.renderFlows || (typeof renderFlows==='function'?renderFlows:null);
  var oldRenderExchangeTab = window.renderExchangeTab || (typeof renderExchangeTab==='function'?renderExchangeTab:null);
  var oldRenderFuhuiTab = window.renderFuhuiTab || (typeof renderFuhuiTab==='function'?renderFuhuiTab:null);
  var oldSaveExchangeQuick = window.saveExchangeQuick || (typeof saveExchangeQuick==='function'?saveExchangeQuick:null);
  var oldSaveFuhuiQuick = window.saveFuhuiQuick || (typeof saveFuhuiQuick==='function'?saveFuhuiQuick:null);

  function E(x){try{return escHtml(x)}catch(e){return String(x??'').replace(/[&<>"']/g,function(m){return {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]})}}

  function escJs(x){return String(x||'').replace(/\\/g,'\\\\').replace(/'/g,"\\'")}

  function taskBtn(group, value, label, sub){
    var current='';
    try{
      if(group==='money')current=flowQuickType||'';
      if(group==='exchange')current=flowQuickType||'';
      if(group==='fuhui')current=fhQuickType||'';
    }catch(e){}
    var active=(window.qdV19FlowGroup===group && current===value) ? ' active' : '';
    return '<button class="qd-v19-task'+active+'" onclick="qdV19SelectFlowTask(\''+group+'\',\''+escJs(value)+'\')">'+E(label)+'<small>'+E(sub||'')+'</small></button>';
  }

  function groupHtml(group, title, sub, inner){
    var open=!!(window.qdV19OpenGroups&&window.qdV19OpenGroups[group]);
    return '<div class="qd-v19-group '+(open?'open':'')+'"><button class="qd-v19-group-title" onclick="qdV19ToggleFlowGroup(\''+group+'\')"><div><strong>'+E(title)+'</strong><span>'+E(sub||'')+'</span></div><div class="qd-v19-chev">'+(open?'−':'+')+'</div></button><div class="qd-v19-children">'+inner+'</div></div>';
  }

  window.qdV19ToggleFlowGroup=function(group){
    window.qdV19OpenGroups=window.qdV19OpenGroups||{};
    var willOpen=!window.qdV19OpenGroups[group];
    Object.keys(window.qdV19OpenGroups).forEach(function(k){window.qdV19OpenGroups[k]=false;});
    window.qdV19OpenGroups[group]=willOpen;
    if(willOpen)window.qdV19FlowGroup=group;
    try{renderFlows()}catch(e){console.error(e)}
  };

  window.qdV19SelectFlowTask=function(group,value){
    window.qdV19FlowGroup=group;
    window.qdV19OpenGroups=window.qdV19OpenGroups||{};
    Object.keys(window.qdV19OpenGroups).forEach(function(k){window.qdV19OpenGroups[k]=false;});
    window.qdV19OpenGroups[group]=true;
    try{
      if(group==='money'){ flowQuickType=value; }
      if(group==='exchange'){ flowQuickType=value; }
      if(group==='fuhui'){ fhQuickType=value; }
    }catch(e){}
    try{renderFlows()}catch(e){console.error(e)}
  };

  function leftHtml(){
    var money = [
      ['Sạp trả vào ví Quang','Sạp trả vào ví Quang','Thu tiền từ chủ sạp về ví/đối tác nhận'],
      ['Sạp chuyển cho chủ hàng','Sạp chuyển cho chủ hàng','Chủ sạp chuyển thẳng cho chủ hàng/người thụ hưởng'],
      ['Trả chủ hàng','Trả chủ hàng','Quang trả tiền cho chủ hàng'],
      ['Đổi nợ chủ hàng','Đổi nợ chủ hàng','Đổi công nợ CNY/VND cho chủ hàng'],
      ['Chuyển vị trí','Chuyển vị trí','Chuyển tiền giữa ví/người giữ tiền']
    ].map(function(x){return taskBtn('money',x[0],x[1],x[2])}).join('');
    var exchange = [
      ['Bán CNY','Bán CNY','Bán CNY cho đối tác'],
      ['Chốt tỷ giá','Chốt tỷ giá','Chốt tỷ giá 1 dòng hoặc nhiều dòng'],
      ['Đối tác trả VND','Đối tác trả VND','Đối tác chuyển VND về ví tôi'],
      ['Tôi bù/trả đối tác','Tôi bù/trả đối tác','Tôi hoàn/bù tiền cho đối tác']
    ].map(function(x){return taskBtn('exchange',x[0],x[1],x[2])}).join('');
    var fuhui = [
      ['Chuyển 付汇','Chuyển 付汇','Nhận/chuyển tiền vào hồ sơ 付汇'],
      ['付汇','付汇','Xử lý nghiệp vụ 付汇'],
      ['Bán tệ','Bán tệ','Bán tệ trong luồng 付汇'],
      ['Chốt tỷ giá','Chốt tỷ giá','Chốt tỷ giá hồ sơ 付汇'],
      ['Tất toán','Tất toán','Tất toán hồ sơ 付汇']
    ].map(function(x){return taskBtn('fuhui',x[0],x[1],x[2])}).join('');
    return '<div class="qd-v19-flow-left"><div class="qd-v19-left-head"><h2>Tác vụ dòng tiền</h2><p>Chọn nhóm bên dưới, rồi chọn tác vụ con để mở form cũ tương ứng.</p></div><div class="qd-v19-groups">'+
      groupHtml('money','Tiền','Sạp trả, trả chủ hàng, đổi nợ, chuyển vị trí',money)+
      groupHtml('exchange','Đổi tiền','Bán CNY, chốt tỷ giá, đối tác trả VND',exchange)+
      groupHtml('fuhui','付汇','Chuyển 付汇, bán tệ, chốt tỷ giá, tất toán',fuhui)+
      '</div></div>';
  }

  function captureOldHtml(){
    var flowsPane=document.getElementById('flows'), exchangePane=document.getElementById('exchange'), fuhuiPane=document.getElementById('fuhui');
    var money='', exchange='', fuhui='';
    try{ if(oldRenderFlows){oldRenderFlows(); money=flowsPane?flowsPane.innerHTML:'';} }catch(e){money='<div class="card">Lỗi render Tiền: '+E(e.message||e)+'</div>';}
    try{ if(oldRenderExchangeTab){oldRenderExchangeTab(); exchange=exchangePane?exchangePane.innerHTML:'';} }catch(e){exchange='<div class="card">Lỗi render Đổi tiền: '+E(e.message||e)+'</div>';}
    try{ if(oldRenderFuhuiTab){oldRenderFuhuiTab(); fuhui=fuhuiPane?fuhuiPane.innerHTML:'';} }catch(e){fuhui='<div class="card">Lỗi render 付汇: '+E(e.message||e)+'</div>';}
    exchange=String(exchange).replace(/renderExchangeTab\(\)/g,'renderFlows()');
    fuhui=String(fuhui).replace(/renderFuhuiTab\(\)/g,'renderFlows()');
    return {money:money, exchange:exchange, fuhui:fuhui};
  }

  function currentTitle(){
    try{
      if(window.qdV19FlowGroup==='money')return 'Tiền · '+(flowQuickType||'Sạp trả vào ví Quang');
      if(window.qdV19FlowGroup==='exchange')return 'Đổi tiền · '+(flowQuickType||'Bán CNY');
      if(window.qdV19FlowGroup==='fuhui')return '付汇 · '+(fhQuickType||'Chuyển 付汇');
    }catch(e){}
    return 'Dòng tiền';
  }

  window.renderFlows=function(){
    setTitle();
    if(!oldRenderFlows)return;
    var pane=document.getElementById('flows'); if(!pane)return;
    var old=captureOldHtml();
    var content=old.money;
    if(window.qdV19FlowGroup==='exchange')content=old.exchange;
    if(window.qdV19FlowGroup==='fuhui')content=old.fuhui;
    pane.innerHTML =
      '<div class="qd-v19-flow-shell">'+
        leftHtml()+
        '<div class="qd-v19-flow-right">'+
          '<div class="qd-v19-right-head"><div><h2>'+E(currentTitle())+'</h2><p>Form bên dưới giữ theo app cũ, chỉ đổi bố cục điều hướng.</p></div><div class="qd-v19-badge">V19 UI upgrade</div></div>'+
          '<div class="qd-v19-old-form-wrap">'+content+'</div>'+
        '</div>'+
      '</div>';
  };
  try{renderFlows=window.renderFlows}catch(e){}

  if(oldSaveExchangeQuick){
    window.saveExchangeQuick=async function(){
      var r=await oldSaveExchangeQuick.apply(this,arguments);
      if(window.qdV19FlowGroup==='exchange')try{renderFlows()}catch(e){}
      return r;
    };
    try{saveExchangeQuick=window.saveExchangeQuick}catch(e){}
  }
  if(oldSaveFuhuiQuick){
    window.saveFuhuiQuick=async function(){
      var r=await oldSaveFuhuiQuick.apply(this,arguments);
      if(window.qdV19FlowGroup==='fuhui')try{renderFlows()}catch(e){}
      return r;
    };
    try{saveFuhuiQuick=window.saveFuhuiQuick}catch(e){}
  }

  var oldShowTab=window.showTab||(typeof showTab==='function'?showTab:null);
  if(oldShowTab&&!oldShowTab.qdV19Wrap){
    window.showTab=function(id,btn){
      var fromMainFlowTab=(id==='flows' && !!btn);
      if(id==='exchange'){id='flows';window.qdV19FlowGroup='exchange';fromMainFlowTab=true;}
      if(id==='fuhui'){id='flows';window.qdV19FlowGroup='fuhui';fromMainFlowTab=true;}
      if(fromMainFlowTab)window.qdV19OpenGroups={};
      return oldShowTab.call(this,id,btn);
    };
    window.showTab.qdV19Wrap=true;
    try{showTab=window.showTab}catch(e){}
  }

  setTitle();
  if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',setTitle);else setTimeout(setTitle,0);
})();

