 window.qdV1927SaveAddLot=async function(){
   try{
     await requireLogin();
     var mode=val("qd1927LotType")||"Thông quan", owner=val("qd1927Owner");
     if(!owner)throw new Error("Chưa chọn chủ hàng.");
     var row={code:val("qd1927Code")||nextCode(owner),owner:owner,lotType:mode,type:mode,date:val("qd1927Date")||today(),status:(mode==="Bán hộ")?"Đang lên chợ":"Chờ bốc",truck:val("qd1927Truck"),mooc:val("qd1927Mooc"),containerNo:val("qd1927Container"),cnTruck:val("qd1927CnTruck"),cnMooc:val("qd1927CnMooc"),brandCn:val("qd1927Brand"),brand:val("qd1927Brand"),origin:val("qd1927Origin"),borderGate:val("qd1927BorderGate"),growCode:val("qd1927GrowCode"),grow_code:val("qd1927GrowCode"),packCode:val("qd1927PackCode"),pack_code:val("qd1927PackCode"),market:val("qd1927Market"),cnMarket:val("qd1927Market"),stall:val("qd1927Stall"),lawProvider:val("qd1927LawProvider"),hasCtv:checked("qd1927HasCtv"),has_ctv:checked("qd1927HasCtv"),note:val("qd1927Note")};
     var ins;
     if(window.supa&&typeof toLotDb==="function"&&typeof fromLotDb==="function"){
       var db=toLotDb(row);
       if(row.growCode)db.grow_code=row.growCode; if(row.packCode)db.pack_code=row.packCode;
       var noteParts=[]; if(row.lawProvider)noteParts.push("[[LAW_PROVIDER:"+row.lawProvider+"]]"); if(row.hasCtv)noteParts.push("[[HAS_CTV:1]]");
       if(noteParts.length)db.note=(db.note?db.note+" ":"")+noteParts.join(" ");
       var r=await supa.from("lots").insert(db).select().single();
       if(r.error){delete db.grow_code;delete db.pack_code;r=await supa.from("lots").insert(db).select().single();if(r.error)throw r.error}
       ins=fromLotDb(r.data); ins.lawProvider=row.lawProvider; ins.hasCtv=row.hasCtv;
     }else ins=Object.assign({id:"local-lot-"+Date.now()},row);
     data.lots.unshift(ins);
     var savedItems=await saveItems(collectItems(ins.id)); if(savedItems.length)data.lotItems.push.apply(data.lotItems,savedItems);
     var savedCosts=await saveCosts(collectCosts(ins.id)); if(savedCosts.length)data.lotCosts.push.apply(data.lotCosts,savedCosts);
     selectedLotId=ins.id; window.qdV1915SelectedLotId=ins.id;
     var m=document.getElementById("qdV1927AddLotModal"); if(m)m.remove();
     try{msg("Đã ghi lô.")}catch(_){}
     try{renderTrack()}catch(_){}
   }catch(e){try{msg(e.message||String(e),"err")}catch(_){alert(e.message||e)}}
 };

