 function groupName(r){if(isFh(r))return "付汇";if(r.type==="Đổi tiền"||String(r.note||"").indexOf("[[QD_EXCHANGE:")>=0)return "Đổi tiền";return "Tiền"}
 function summary(r){if(isIn(r))return "IN hệ thống → "+P(r.to);if(isOut(r))return "OUT hệ thống từ "+P(r.from);if(r.type==="Chuyển vị trí")return "Chuyển ví: "+P(r.from)+" → "+P(r.to);if(isFh(r)){if(has(r,mFIn))return "Chuyển FH: "+P(r.from)+" → FH";if(has(r,mFMove))return "FH → "+P(r.to)+" / phí 0.1%";if(has(r,mFSell))return "Bán tệ: "+P(r.from)+" → "+P(r.to);if(has(r,mFRate))return "Chốt tỷ giá FH cho "+P(r.owner);if(has(r,mFSettle))return "Tất toán FH cho "+P(r.owner);return "付汇"}try{return flowSummary(r)}catch(_){return [P(r.from),P(r.to)].filter(Boolean).join(" → ")}}
 function money(r){return has(r,mFSell)?(F(r.amount,"CNY")+" → "+F(r.toAmount,"VND")):F(r.amount,r.currency)}
 window.renderFlows=function(){var pane=document.getElementById("flows"); if(!pane)return;if(openGroup && !(ACTIONS[openGroup]||[]).some(function(a){return a[0]===activeAction}))activeAction="";var groups=GROUPS.map(function(g){var open=openGroup===g[0];var acts=(ACTIONS[g[0]]||[]).map(function(a){return '<button class="qd27-action '+(activeAction===a[0]?'active':'')+'" onclick="qdV1927SelectFlowAction(\''+a[0]+'\',\''+g[0]+'\')"><b>'+E(a[1])+'</b><span>'+E(a[2])+'</span></button>'}).join("");return '<div class="qd27-group '+(open?'open':'')+'"><button class="qd27-group-head" onclick="qdV1927ToggleFlowGroup(\''+g[0]+'\')"><span class="qd27-group-title">'+E(g[1])+'</span><span class="qd27-group-sub">'+E(g[2])+'</span></button><div class="qd27-actions">'+acts+'</div></div>'}).join("");var rows=(data.flows||[]).filter(function(r){try{return !isOpeningFlow(r)}catch(_){return true}}).slice().reverse().slice(0,80);var history=rows.length?rows.map(function(r){return '<div class="qd27-row"><div><span class="qd27-badge">'+E(groupName(r))+'</span></div><div><div class="qd27-main">'+E(summary(r))+'</div><div class="qd27-sub">'+E([r.date,r.ref?("Mã: "+r.ref):"",cleanNote(r.note)].filter(Boolean).join(" · "))+'</div></div><div class="qd27-money">'+E(money(r))+'</div><div><button class="qd27-mini" onclick="editFlow(\''+E(r.id)+'\')">Sửa</button></div></div>'}).join(""):'<div class="qd27-sub">Chưa có giao dịch.</div>';pane.innerHTML='<div class="qd27-flow-clean"><section class="qd27-flow-left"><h2>Dòng tiền</h2>'+groups+'</section><section>'+formHtml()+'<div class="qd27-flow-history"><h3>Lịch sử gần đây</h3>'+history+'</div></section></div>';setTimeout(qdV1927FlowSpecialChange,0)};
 var oldCalc=window.calc||(typeof calc==="function"?calc:null);if(oldCalc&&!oldCalc.qd27FlowLayoutFhCleanWrap){window.calc=function(){var res=oldCalc.apply(this,arguments);function add(arr,fields,delta){if(!delta)return;var hit=(arr||[]).find(function(r){return Object.keys(fields).every(function(k){return String(r[k]||"")===String(fields[k]||"")})});if(hit)hit.amount=N(hit.amount)+delta;else (arr||[]).push(Object.assign({amount:delta},fields))}(data.flows||[]).forEach(function(r){var a=N(r.amount), fee=feeOf(a); if(!a)return;if(isIn(r)){add(res.locationBal,{location:r.to,currency:r.currency},a);add(res.detail,{owner:"QUANG",location:r.to,currency:r.currency},a)}else if(isOut(r)){add(res.locationBal,{location:r.from,currency:r.currency},-a);add(res.detail,{owner:"QUANG",location:r.from,currency:r.currency},-a)}else if(has(r,mFIn)){add(res.detail,{owner:r.from||r.owner,location:FH,currency:"CNY"},a);add(res.detail,{owner:r.from||r.owner,location:"Phí FH",currency:"CNY"},-fee);add(res.detail,{owner:FH,location:FH,currency:"CNY"},a)}else if(has(r,mFMove)){add(res.detail,{owner:FH,location:FH,currency:"CNY"},-a-fee);add(res.locationBal,{location:r.to,currency:"CNY"},a);add(res.detail,{owner:"QUANG",location:r.to,currency:"CNY"},a)}else if(has(r,mFSell)){add(res.locationBal,{location:r.from,currency:"CNY"},-a);add(res.locationBal,{location:r.to,currency:"VND"},N(r.toAmount));add(res.detail,{owner:"QUANG",location:r.from,currency:"CNY"},-a);add(res.detail,{owner:"QUANG",location:r.to,currency:"VND"},N(r.toAmount))}else if(has(r,mFRate)){var v=N(r.toAmount)||(N(r.rate)?Math.round(a*N(r.rate)):0);add(res.detail,{owner:r.owner,location:"Chốt FH",currency:"CNY"},-a);add(res.detail,{owner:r.owner,location:"Chốt FH",currency:"VND"},v)}else if(has(r,mFSettle)){add(res.locationBal,{location:r.from,currency:r.currency},-a);add(res.detail,{owner:r.owner,location:"Tất toán FH",currency:r.currency},-a)}});return res};window.calc.qd27FlowLayoutFhCleanWrap=true;try{calc=window.calc}catch(_){}}
